import type { Meta, StoryObj } from '@storybook/react';
import { ConfirmDialog } from './ConfirmDialog';
import { Button } from './Button';
import { useState } from 'react';

const meta = {
  title: 'UI/ConfirmDialog',
  component: ConfirmDialog,
  parameters: {
    layout: 'centered',
  },
  tags: ['autodocs'],
  argTypes: {
    title: { control: 'text' },
    message: { control: 'text' },
    confirmLabel: { control: 'text' },
    cancelLabel: { control: 'text' },
    variant: { control: 'select', options: ['danger', 'info', 'warning', 'success'] },
    isLoading: { control: 'boolean' },
  },
} satisfies Meta<typeof ConfirmDialog>;

export default meta;
type Story = StoryObj<typeof meta>;

const ConfirmDialogWrapper = (args: any) => {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <div>
      <Button variant="danger" onClick={() => setIsOpen(true)}>Delete Item</Button>
      <ConfirmDialog
        {...args}
        isOpen={isOpen}
        onClose={() => setIsOpen(false)}
        onConfirm={() => {
          alert('Confirmed!');
          setIsOpen(false);
        }}
      />
    </div>
  );
};

export const Default: Story = {
  render: (args) => <ConfirmDialogWrapper {...args} />,
  args: {
    title: 'Delete Item',
    message: 'Are you sure you want to delete this item? This action cannot be undone.',
    confirmLabel: 'Delete',
    cancelLabel: 'Cancel',
    variant: 'danger',
  },
};

export const Info: Story = {
  render: (args) => <ConfirmDialogWrapper {...args} />,
  args: {
    title: 'Confirm Action',
    message: 'Do you want to proceed with this action?',
    confirmLabel: 'Yes',
    cancelLabel: 'No',
    variant: 'info',
  },
};

export const Loading: Story = {
  render: (args) => <ConfirmDialogWrapper {...args} />,
  args: {
    title: 'Processing',
    message: 'Please wait while we process your request...',
    isLoading: true,
  },
};

import React, { useState, useRef, useEffect } from 'react';
import type { ReactNode } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { cn } from '@/utils/cn';

interface DropdownProps {
  trigger: ReactNode;
  children: ReactNode;
  align?: 'left' | 'right';
  className?: string;
  width?: string;
}

export const Dropdown: React.FC<DropdownProps> = ({
  trigger,
  children,
  align = 'right',
  className,
  width = 'w-48'
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div className={cn("relative inline-block text-left", className)} ref={dropdownRef}>
      <div onClick={() => setIsOpen(!isOpen)} className="cursor-pointer">
        {trigger}
      </div>

      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: -10 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: -10 }}
            transition={{ duration: 0.1 }}
            className={cn(
              "absolute z-[100] mt-2 rounded-md shadow-lg bg-white dark:bg-slate-800 ring-1 ring-black ring-opacity-5 focus:outline-none origin-top",
              align === 'right' ? 'right-0' : 'left-0',
              width
            )}
          >
            <div className="py-1" role="menu" aria-orientation="vertical" aria-labelledby="options-menu">
              {React.Children.map(children, (child) => {
                 if (React.isValidElement(child)) {
                    return React.cloneElement(child, {
                        // @ts-ignore
                        onClick: (e: any) => {
                            (child as any).props.onClick?.(e);
                            setIsOpen(false);
                        }
                    });
                 }
                 return child;
              })}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

interface DropdownItemProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  icon?: React.ReactNode;
  variant?: 'default' | 'danger';
}

export const DropdownItem: React.FC<DropdownItemProps> = ({ 
  children, 
  icon, 
  variant = 'default', 
  className,
  ...props 
}) => {
  return (
    <button
      className={cn(
        "group flex w-full items-center px-4 py-2 text-sm transition-colors",
        variant === 'danger' 
          ? "text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20" 
          : "text-gray-700 dark:text-gray-200 hover:bg-gray-100 dark:hover:bg-gray-700",
        className
      )}
      role="menuitem"
      {...props}
    >
      {icon && (
        <span className={cn(
          "mr-3 h-4 w-4",
          variant === 'danger' ? "text-red-500" : "text-gray-400 group-hover:text-gray-500"
        )}>
          {icon}
        </span>
      )}
      {children}
    </button>
  );
};

