describe('useRoles hooks', () => {
    beforeEach(() => {
        vi.clearAllMocks();
    });

    describe('useRoles', () => {
        it('should fetch roles with params', async () => {
            const mockData = {
                success: true,
                message: '',
                statusCode: 200,
                data: {
                    items: [{ code: 'admin', name: 'Admin' }],
                    totalItems: 1,
                    pageIndex: 1,
                    pageSize: 10,
                    totalPages: 1,
                    hasPreviousPage: false,
                    hasNextPage: false
                }
            };
            (roleService.search as any).mockResolvedValue(mockData);

            const params = { pageIndex: 1, pageSize: 10 };
            const { result } = renderHook(() => useRoles(params), { wrapper });

            await waitFor(() => expect(result.current.isSuccess).toBe(true));
            expect(result.current.data).toEqual(mockData);
            expect(roleService.search).toHaveBeenCalledWith(params);
        });

        it('should handle error states', async () => {
            (roleService.search as any).mockRejectedValue(new Error('Fetch failed'));

            const { result } = renderHook(() => useRoles({}), { wrapper });

            await waitFor(() => expect(result.current.isError).toBe(true));
            expect(result.current.error).toBeDefined();
        });
    });

    describe('useRole', () => {
        it('should fetch a single role by code', async () => {
            const mockRole = { code: 'admin', name: 'Admin', permissions: [] };
            const mockResponse = { success: true, message: '', statusCode: 200, data: mockRole };
            (roleService.getByCode as any).mockResolvedValue(mockResponse);

            const { result } = renderHook(() => useRole('admin'), { wrapper });

            await waitFor(() => expect(result.current.isSuccess).toBe(true));
            expect(result.current.data).toEqual(mockResponse);
            expect(roleService.getByCode).toHaveBeenCalledWith('admin');
        });

        it('should not fetch if code is empty', () => {
            renderHook(() => useRole(''), { wrapper });
            expect(roleService.getByCode).not.toHaveBeenCalled();
        });
    });
});

import { useEffect, useRef, RefObject } from 'react';

type Handler = (event: MouseEvent | TouchEvent) => void;

export const useClickOutside = <T extends HTMLElement = HTMLElement>(
    handler: Handler
): RefObject<T> => {
    const ref = useRef<T>(null);

    useEffect(() => {
        const listener = (event: MouseEvent | TouchEvent) => {
            const el = ref?.current;

            // Do nothing if clicking ref's element or descendent elements
            if (!el || el.contains(event.target as Node)) {
                return;
            }

            handler(event);
        };

        document.addEventListener('mousedown', listener);
        document.addEventListener('touchstart', listener);

        return () => {
            document.removeEventListener('mousedown', listener);
            document.removeEventListener('touchstart', listener);
        };
    }, [ref, handler]);

    return ref as any;
};

import { useState, useMemo } from 'react';
import { applyClientFilters } from '@/utils/queryHelper';
import { SearchCondition } from '@/services/api';

interface UseDataTableProps<T> {
    data: T[];
    filterFn?: (item: T, filterTerm: string, filterField?: string) => boolean;
    initialSort?: { field: keyof T; direction: 'asc' | 'desc' };
}

export const useDataTable = <T extends { id: string | number } & Record<string, any>>({
    data,
    filterFn,
    initialSort,
}: UseDataTableProps<T>) => {
    // Selection
    const [selectedIds, setSelectedIds] = useState<Set<string | number>>(new Set());

    // Search & Filter
    const [searchQuery, setSearchQuery] = useState('');
    const [searchField, setSearchField] = useState<string>('all');

    // Sort
    const [sortConfig, setSortConfig] = useState<{ field: keyof T; direction: 'asc' | 'desc' } | null>(
        initialSort || null
    );

    // Pagination
    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(10);

    // --- Logic ---

    // 1. Filter
    const filteredData = useMemo(() => {
        let result = data;

        // Apply external filters (complex SearchDTOs) logic locally if data is all here
        // Note: If server-side pagination is used, 'data' is usually just current page, so this runs on that subset.
        // But for client-side tables, this is powerful.
        // We can extend this hook to accept 'filters' prop if needed, 
        // but for now let's keep searchField/searchQuery behavior and map it to a SearchDTO.

        if (searchQuery) {
            const lowerQuery = searchQuery.toLowerCase();
            // Reuse the simple logic OR use the new helper?
            // Let's use the new helper for single field search to ensure consistency
            if (searchField !== 'all') {
                result = applyClientFilters(result, [{
                    searchField: searchField,
                    searchCondition: SearchCondition.Contains,
                    searchValue: lowerQuery
                }]);
            } else {
                // Fallback to "All Fields" search which is not in SearchDTO standard usually
                result = result.filter(item =>
                    Object.values(item).some(val =>
                        String(val).toLowerCase().includes(lowerQuery)
                    )
                );
            }
        }

        if (filterFn) {
            result = result.filter(item => filterFn(item, searchQuery.toLowerCase(), searchField));
        }

        return result;
    }, [data, searchQuery, searchField, filterFn]);

    // 2. Sort
    const sortedData = useMemo(() => {
        if (!sortConfig) return filteredData;

        return [...filteredData].sort((a, b) => {
            const aVal = a[sortConfig.field];
            const bVal = b[sortConfig.field];

            if (aVal < bVal) return sortConfig.direction === 'asc' ? -1 : 1;
            if (aVal > bVal) return sortConfig.direction === 'asc' ? 1 : -1;
            return 0;
        });
    }, [filteredData, sortConfig]);

    // 3. Paginate
    const paginatedData = useMemo(() => {
        const startIndex = (currentPage - 1) * itemsPerPage;
        return sortedData.slice(startIndex, startIndex + itemsPerPage);
    }, [sortedData, currentPage, itemsPerPage]);

    const totalPages = Math.ceil(filteredData.length / itemsPerPage);

    // Handlers
    const handleSelectAll = (checked: boolean) => {
        if (checked) {
            // Select all visible items (or all filtered items depending on UX preference)
            // Usually users expect "Select All" to select current page or all 
            // Let's implement select all filtered for power usage
            setSelectedIds(new Set(filteredData.map(d => d.id)));
        } else {
            setSelectedIds(new Set());
        }
    };

    const handleSelectRow = (id: string | number) => {
        setSelectedIds((prev) => {
            const next = new Set(prev);
            if (next.has(id)) {
                next.delete(id);
            } else {
                next.add(id);
            }
            return next;
        });
    };

    const handleSort = (field: keyof T) => {
        setSortConfig((current) => {
            if (current?.field === field) {
                return { field, direction: current.direction === 'asc' ? 'desc' : 'asc' };
            }
            return { field, direction: 'asc' };
        });
    };

    return {
        // State
        selectedIds,
        searchQuery,
        searchField,
        sortConfig,
        currentPage,
        itemsPerPage,

        // Data
        data: paginatedData,
        totalItems: filteredData.length,
        totalPages,

        // Setters
        setSearchQuery,
        setSearchField,
        setItemsPerPage,
        setCurrentPage,

        // Actions
        handleSelectAll,
        handleSelectRow,
        handleSort,
        resetSelection: () => setSelectedIds(new Set()),
    };
};

import { useState, useCallback } from 'react';
import { useMutation, useQueryClient, QueryKey } from '@tanstack/react-query';
import { useToast } from '@/store';
import { useTranslation } from 'react-i18next';

export interface EntityService<T, CreateDto, UpdateDto> {
    create: (data: CreateDto) => Promise<any>;
    update: (id: any, data: UpdateDto) => Promise<any>;
    delete: (id: any) => Promise<any>;
    getByCode?: (code: any, params?: any) => Promise<any>; // Optional fetch detail method
}

interface UseEntityManagerOptions<T, CreateDto, UpdateDto> {
    service: EntityService<T, CreateDto, UpdateDto>;
    queryKey: QueryKey;
    includeChildrenOnEdit?: boolean; // New option
    translations?: {
        createSuccess?: string;
        createError?: string;
        updateSuccess?: string;
        updateError?: string;
        deleteSuccess?: string;
        deleteError?: string;
    };
}

export const useEntityManager = <T extends { code?: string; id?: string | number }, CreateDto = Partial<T>, UpdateDto = Partial<T>>({
    service,
    queryKey,
    includeChildrenOnEdit = false,
    translations,
}: UseEntityManagerOptions<T, CreateDto, UpdateDto>) => {
    const { t } = useTranslation();
    const queryClient = useQueryClient();
    const toast = useToast();

    const [isFormOpen, setIsFormOpen] = useState(false);
    const [editingItem, setEditingItem] = useState<T | null>(null);
    const [itemToDelete, setItemToDelete] = useState<T | null>(null);
    const [isFetchingDetail, setIsFetchingDetail] = useState(false);

    const createMutation = useMutation({
        mutationFn: (data: CreateDto) => service.create(data),
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey });
            toast.success(translations?.createSuccess || t('common.createSuccess'));
            setIsFormOpen(false);
        },
        onError: (error: Error) => {
            toast.error(error?.message || translations?.createError || t('common.createError'));
        },
    });

    const updateMutation = useMutation({
        mutationFn: ({ id, data }: { id: string | number; data: UpdateDto }) => service.update(id, data),
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey });
            toast.success(translations?.updateSuccess || t('common.updateSuccess'));
            setIsFormOpen(false);
            setEditingItem(null);
        },
        onError: (error: Error) => {
            toast.error(error?.message || translations?.updateError || t('common.updateError'));
        },
    });

    const deleteMutation = useMutation({
        mutationFn: (id: string | number) => service.delete(id),
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey });
            toast.success(translations?.deleteSuccess || t('common.deleteSuccess'));
            setItemToDelete(null);
        },
        onError: (error: Error) => {
            toast.error(error?.message || translations?.deleteError || t('common.deleteError'));
        },
    });

    const openCreate = useCallback(() => {
        setEditingItem(null);
        setIsFormOpen(true);
    }, []);

    const openEdit = useCallback(async (item: T) => {
        setEditingItem(item);
        setIsFormOpen(true);

        // Try to fetch fresh details if service supports it
        const id = item.code;
        if (service.getByCode && id) {
            setIsFetchingDetail(true);
            try {
                const response = await service.getByCode(id, includeChildrenOnEdit ? { includeChildren: true } : undefined);
                // Check if response wraps data in ApiResponse logic (success/data props)
                if (response && response.success && response.data) {
                    setEditingItem(response.data);
                } else if (response) {
                    // Fallback if response is direct object or different format
                    setEditingItem(response as T);
                }
            } catch (err) {
                console.error("Failed to fetch fresh item details", err);
                // Optionally toast warning?
            } finally {
                setIsFetchingDetail(false);
            }
        }
    }, [service, includeChildrenOnEdit]);

    const closeForm = useCallback(() => {
        setIsFormOpen(false);
        setEditingItem(null);
    }, []);

    const confirmDelete = useCallback((item: T) => {
        setItemToDelete(item);
    }, []);

    const cancelDelete = useCallback(() => {
        setItemToDelete(null);
    }, []);

    const processCreate = useCallback((data: CreateDto) => {
        createMutation.mutate(data);
    }, [createMutation]);

    const processUpdate = useCallback((id: any, data: UpdateDto) => {
        updateMutation.mutate({ id, data });
    }, [updateMutation]);

    const processDelete = useCallback((id: any) => {
        deleteMutation.mutate(id);
    }, [deleteMutation]);

    return {
        // State
        isFormOpen,
        editingItem,
        itemToDelete,
        isFetchingDetail,

        // Actions
        openCreate,
        openEdit,
        closeForm,
        confirmDelete,
        cancelDelete,

        // Processors
        create: processCreate,
        update: processUpdate,
        delete: processDelete,

        // Mutations (full objects if needed)
        createMutation,
        updateMutation,
        deleteMutation,

        // Loading states
        isLoading: createMutation.isPending || updateMutation.isPending || deleteMutation.isPending,
        isCreating: createMutation.isPending,
        isUpdating: updateMutation.isPending,
        isDeleting: deleteMutation.isPending,
    };
};

import { useState, useCallback } from 'react';
import { exportToExcel, ExportColumn } from '@/utils/export';

interface UseExportOptions<T> {
    defaultFilename?: string;
    defaultColumns?: ExportColumn<T>[];
}

export function useExport<T extends Record<string, any>>(initialOptions: UseExportOptions<T> = {}) {
    const [isExporting, setIsExporting] = useState(false);

    const exportData = useCallback(async (
        data: T[] | Promise<T[]>,
        filename: string = initialOptions.defaultFilename || 'export',
        columns?: ExportColumn<T>[]
    ) => {
        setIsExporting(true);
        try {
            const resolvedData = await Promise.resolve(data);
            const cols = columns || initialOptions.defaultColumns;
            await exportToExcel(resolvedData, filename, cols);
        } catch (error) {
            console.error('Export failed:', error);
            throw error;
        } finally {
            setIsExporting(false);
        }
    }, [initialOptions.defaultFilename, initialOptions.defaultColumns]);

    return { isExporting, exportData };
}

/**
 * useOrders hook - React Query hooks for Order operations
 */
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { orderService, type UpdateOrderRequest } from '@/services/orderService';
import { SearchCondition } from '@/services/baseService';

export function useOrders(params?: {
    pageIndex?: number;
    pageSize?: number;
    status?: string;
}) {
    return useQuery({
        queryKey: ['orders', params],
        queryFn: () => orderService.search({
            pageIndex: params?.pageIndex || 1,
            pageSize: params?.pageSize || 10,
            search: params?.status,
            searchField: params?.status ? 'status' : undefined
        }),
        select: (response) => {
            const pageSize = params?.pageSize || 10;
            const pageIndex = params?.pageIndex || 1;
            const totalItems = response.data?.totalItems || 0;
            const totalPages = Math.ceil(totalItems / pageSize);

            // Deduplicate
            const uniqueItems = Array.from(new Map((response.data?.items || []).map(item => [item.code, item])).values());

            return {
                orders: uniqueItems,
                totalPages,
                totalItems,
                pageNumber: pageIndex
            };
        }
    });
}

export function useAdminOrders(params?: {
    pageIndex?: number;
    pageSize?: number;
    filters?: Record<string, any>;
}) {
    const searchFilters: { field: string; value: string; operator?: SearchCondition }[] = [];
    const searchTerm = params?.filters?.search;

    // Convert filters to array for backend
    if (params?.filters) {
        Object.entries(params.filters).forEach(([key, value]) => {
            if (value && key !== 'search') {
                searchFilters.push({ field: key, value: String(value) });
            }
        });
    }

    return useQuery({
        queryKey: ['admin-orders', params],
        queryFn: () => orderService.search({
            pageIndex: params?.pageIndex || 1,
            pageSize: params?.pageSize || 10,
            search: searchTerm,
            searchField: 'all', // Backend will search across default fields if not specified
            filters: searchFilters.length > 0 ? searchFilters : undefined
        }),
        select: (response) => {
            const pageSize = params?.pageSize || 10;
            const pageIndex = params?.pageIndex || 1;
            const totalItems = response.data?.totalItems || 0;
            const totalPages = Math.ceil(totalItems / pageSize);

            // Deduplicate
            const uniqueItems = Array.from(new Map((response.data?.items || []).map(item => [item.code, item])).values());

            return {
                orders: uniqueItems,
                totalPages,
                totalItems,
                pageNumber: pageIndex
            };
        }
    });
}

export function useUpdateOrderStatus() {
    const queryClient = useQueryClient();

    return useMutation({
        mutationFn: ({ code, status }: { code: string; status: string }) =>
            orderService.update(code, { status }),
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['orders'] });
            queryClient.invalidateQueries({ queryKey: ['admin-orders'] });
            queryClient.invalidateQueries({ queryKey: ['dashboard-stats'] });
        }
    });
}
export function useOrder(code: string) {
    return useQuery({
        queryKey: ['order', code],
        queryFn: async () => {
            const res = await orderService.getByCode(code);
            if (!res.success || !res.data) {
                throw new Error(res.message || 'Failed to fetch order');
            }
            return res.data;
        },
        enabled: !!code
    });
}

/**
 * React Query hooks for Products
 * Provides data fetching and mutations for product operations
 */

import { useQuery, useMutation, useQueryClient, keepPreviousData } from '@tanstack/react-query';

import { Product } from '@/types';
import { productService, categoryService, type CreateProductRequest, type UpdateProductRequest, type ProductDto } from '@/services/productService';
import { SearchCondition } from '@/services/baseService';
import { getImageUrl } from '@/utils/format';
import { CATEGORY_LIST_FIELDS } from '@/constants/fieldConstants';

// ============ Query Keys ============
export const productKeys = {
    all: ['products'] as const,
    lists: () => [...productKeys.all, 'list'] as const,
    list: (params: Record<string, unknown>) => [...productKeys.lists(), params] as const,
    details: () => [...productKeys.all, 'detail'] as const,
    detail: (code: string) => [...productKeys.details(), code] as const,
    categories: ['categories'] as const,
};


// ============ Query Hooks ============

/**
 * Hook for fetching all categories for selection
 */
export function useCategories(params?: {
    pageIndex?: number;
    pageSize?: number;
    search?: string;
    enabled?: boolean;
    fields?: string[];
}) {
    const {
        enabled,
        pageIndex = 1,
        pageSize = 1000,
        search,
        fields = CATEGORY_LIST_FIELDS
    } = params || {};

    return useQuery({
        queryKey: [...productKeys.categories, { pageIndex, pageSize, search, fields }],
        queryFn: () => categoryService.search({
            pageIndex,
            pageSize,
            search,
            filters: [{ field: 'IsActive', value: true, operator: SearchCondition.Equal }],
            searchField: 'name',
            fields
        }),
        enabled: enabled,
        select: (response) => {
            if (response.success && response.data) {
                return response.data.items || [];
            }
            return [];
        }
    });
}

/**
 * Hook for fetching categories with pagination
 */
export function useCategoriesList(params: {
    pageIndex?: number;
    pageSize?: number;
    search?: string;
    parentCode?: string;
    isActive?: string; // 'true' | 'false'
    fields?: string[];  // Selective columns to fetch
}) {
    const { fields, ...searchParams } = params;

    // Build filters
    const filters: { field: string; value: string; operator?: SearchCondition }[] = [];
    if (searchParams.parentCode) filters.push({ field: 'parentCode', value: searchParams.parentCode });
    if (searchParams.isActive) filters.push({ field: 'isActive', value: searchParams.isActive, operator: SearchCondition.Equal });
    if (searchParams.search) filters.push({ field: 'name', value: searchParams.search, operator: SearchCondition.Contains });


    return useQuery({
        queryKey: [...productKeys.categories, { ...searchParams, fields }],
        queryFn: () => categoryService.search({
            pageIndex: searchParams.pageIndex,
            pageSize: searchParams.pageSize,
            // Search is handled via filters for precise control or generic search
            // If we use baseService search, we can pass filters directly
            filters: filters.length > 0 ? filters : undefined,
            fields,  // Pass fields for selective column fetching
        }),
        placeholderData: keepPreviousData,
        select: (response) => {
            if (response.success && response.data) {
                const pageSize = searchParams.pageSize || 10;
                const pageIndex = searchParams.pageIndex || 1;
                const totalItems = response.data.totalItems;
                const totalPages = Math.ceil(totalItems / pageSize);

                // Deduplicate
                const uniqueItems = Array.from(new Map((response.data.items || []).map(item => [item.code, item])).values());

                return {
                    categories: uniqueItems,
                    totalItems,
                    totalPages,
                    pageNumber: pageIndex,
                    pageSize,
                };
            }
            return {
                categories: [],
                totalItems: 0,
                totalPages: 0,
                pageNumber: 1,
                pageSize: 10,
            };
        }
    });
}

/**
 * Hook for fetching products with pagination and search
 */
export function useProducts(params: {
    pageIndex?: number;
    pageSize?: number;
    search?: string;
    sortField?: string;
    sortDir?: 'asc' | 'desc';
    category?: string;
    brands?: string[];
    minPrice?: number;
    maxPrice?: number;
    rating?: number;
    priceType?: 'all' | 'fixed' | 'contact';
    enabled?: boolean;
    ids?: string[];
    fields?: string[];  // Selective columns to fetch (reduces data transfer)
}) {
    const { enabled = true, fields, ...searchParams } = params;

    // Build filters dynamically
    const filters: { field: string; value: string | string[] | number | number[] | boolean; operator?: SearchCondition }[] = [];

    // 1. Generic/Dynamic params (excluding specific ones)
    Object.entries(searchParams).forEach(([key, value]) => {
        if (['pageIndex', 'pageSize', 'search', 'sortField', 'sortDir', 'brands', 'minPrice', 'maxPrice', 'rating', 'category', 'ids', 'priceType'].includes(key)) return;
        if (value !== undefined && value !== null && value !== '') {
            filters.push({ field: key, value: String(value), operator: SearchCondition.Equal });
        }
    });

    // 0. IDs (Multi-select)
    if (searchParams.ids && searchParams.ids.length > 0) {
        filters.push({
            field: 'Code',
            value: searchParams.ids,
            operator: SearchCondition.In
        });
    }

    // 2. Category (Multi-select)
    if (searchParams.category) {
        if (searchParams.category.includes(',')) {
            const cats = searchParams.category.split(',').map(c => c.trim());
            filters.push({
                field: 'CategoryCode',
                value: cats,
                operator: SearchCondition.In
            });
        } else {
            filters.push({
                field: 'CategoryCode',
                value: searchParams.category,
                operator: SearchCondition.Equal
            });
        }
    }

    // 2. Brands (Multi-select) -> In Operator
    if (searchParams.brands && searchParams.brands.length > 0) {
        filters.push({
            field: 'brand', // Make sure backend entity has 'Brand' property
            value: searchParams.brands,
            operator: SearchCondition.In
        });
    }

    // 3. Price Range
    if (searchParams.minPrice !== undefined) {
        filters.push({ field: 'price', value: searchParams.minPrice, operator: SearchCondition.GreaterThanEqual });
    }
    if (searchParams.maxPrice !== undefined) {
        filters.push({ field: 'price', value: searchParams.maxPrice, operator: SearchCondition.LessThanEqual });
    }

    // 4a. Price Type (Fixed vs Contact)
    if (searchParams.priceType) {
        if (searchParams.priceType === 'contact') {
            filters.push({ field: 'price', value: 0, operator: SearchCondition.Equal });
        } else if (searchParams.priceType === 'fixed') {
            filters.push({ field: 'price', value: 0, operator: SearchCondition.GreaterThan });
        }
    }

    // 4. Rating
    if (searchParams.rating !== undefined && searchParams.rating !== null) {
        filters.push({ field: 'rating', value: searchParams.rating, operator: SearchCondition.GreaterThanEqual });
    }


    return useQuery({
        queryKey: productKeys.list({ ...searchParams, fields }),
        queryFn: () => productService.search({
            pageIndex: searchParams.pageIndex,
            pageSize: searchParams.pageSize,
            search: searchParams.search,
            searchField: 'name',
            sortBy: searchParams.sortField,
            sortDesc: searchParams.sortDir === 'desc',
            filters: filters.length > 0 ? filters : undefined,
            fields,  // Pass fields for selective column fetching
        }),
        enabled,
        placeholderData: keepPreviousData,
        select: (response): {
            products: Product[];
            totalItems: number;
            totalPages: number;
            pageNumber: number;
            pageSize: number;
            hasNextPage: boolean;
            hasPreviousPage: boolean;
        } => {
            if (response.success && response.data) {
                const pageSize = searchParams.pageSize || 10;
                const pageIndex = searchParams.pageIndex || 1;
                const totalItems = response.data.totalItems;
                const totalPages = Math.ceil(totalItems / pageSize);

                // Deduplicate items based on code to prevent UI duplication issues
                const uniqueItems = Array.from(new Map((response.data.items || []).map(item => [item.code, item])).values());

                // Map ProductDto to Frontend Product model
                const products: Product[] = uniqueItems.map((item: any) => ({
                    code: item.code,
                    name: item.name,
                    slug: item.code, // Use code as slug for now
                    description: item.description || '',
                    price: item.price,
                    // Handle image collection casing
                    image: getImageUrl(
                        (item.productImages || item.ProductImages || item.product_images)?.find((img: any) => img.isPrimary)?.imageURL ||
                        (item.productImages || item.ProductImages || item.product_images)?.find((img: any) => img.isPrimary)?.imageUrl ||
                        (item.productImages || item.ProductImages || item.product_images)?.find((img: any) => img.isPrimary)?.ImageURL ||
                        (item.productImages || item.ProductImages || item.product_images)?.[0]?.imageURL ||
                        (item.productImages || item.ProductImages || item.product_images)?.[0]?.imageUrl ||
                        (item.productImages || item.ProductImages || item.product_images)?.[0]?.ImageURL
                    ),
                    images: (item.productImages || item.ProductImages || item.product_images)?.map((img: any) => getImageUrl(img.imageURL || img.imageUrl || img.ImageURL)) || [],
                    // Pass raw DTO for form management
                    productImages: item.productImages || item.ProductImages || item.product_images || [],
                    category: item.categoryName || '',
                    categoryCode: item.categoryCode || '',
                    stock: item.stockQuantity || 0,
                    // Attributes
                    color: item.color,
                    power: item.power,
                    voltage: item.voltage,
                    material: item.material,
                    size: item.size,
                    // Mock/Default values for missing backend fields
                    brand: 'VNVT',
                    rating: 5,
                    reviewCount: 0,
                    isFeatured: false,
                    isNew: true,
                    createdAt: item.createdAt || new Date().toISOString()
                }));

                return {
                    products,
                    totalItems,
                    totalPages,
                    pageNumber: pageIndex,
                    pageSize,
                    hasNextPage: pageIndex < totalPages,
                    hasPreviousPage: pageIndex > 1,
                };
            }
            return {
                products: [],
                totalItems: 0,
                totalPages: 0,
                pageNumber: 1,
                pageSize: 10,
                hasNextPage: false,
                hasPreviousPage: false,
            };
        },
    });
}

/**
