              {promotions.map(p => (
                <option key={p.code} value={p.code}>{p.name} ({p.discountType === 'PERCENTAGE' ? `${p.discountValue}%` : t('common.currency', { value: p.discountValue })})</option>
              ))}
            </select>
          </div>

          <div className="flex items-center gap-2 pt-2">
            <input
              type="checkbox"
              id="isActive"
              className="w-4 h-4 rounded border-tertiary"
              checked={formData.isActive}
              onChange={(e) => setFormData({ ...formData, isActive: e.target.checked })}
            />
            <label htmlFor="isActive" className="text-sm font-medium cursor-pointer">{t('admin.status.active')}</label>
          </div>
        </form>
      </Modal>

      <ConfirmDialog
        isOpen={!!couponToDelete}
        onClose={() => setCouponToDelete(null)}
        onConfirm={() => couponToDelete && deleteMutation.mutate(couponToDelete.code)}
        title={t('common.actions.delete')}
        message={t('messages.confirmDelete')}
        variant="danger"
        isLoading={deleteMutation.isPending}
      />
    </div>
  );
};

export default CouponsPage;

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Mail, Phone, Users, AlertTriangle, Key } from 'lucide-react';
import { Button, Modal, Badge, ConfirmDialog, TableActions, Input, Select, Switch } from '@/components/ui';
import { useToast } from '@/store';
import { formatCurrency, formatDate } from '@/utils/format';
import { DataTable, type DataTableColumn } from '@/components/common/DataTable';
import { AdminPageHeader } from '@/components/admin';
import { useEntityManager } from '@/hooks';
import { customerService, type CustomerDto, type CreateCustomerRequest, type UpdateCustomerRequest } from '@/services';
import { useQuery, useMutation } from '@tanstack/react-query';
import { PaginationDefaults, SortDirection } from '@/constants';
import { StatsCards, StatItem } from '@/components/admin/StatsCards';

export const CustomersPage = () => {
  const { t } = useTranslation();
  const [selectedCustomer, setSelectedCustomer] = useState<CustomerDto | null>(null);
  const [resettingCustomer, setResettingCustomer] = useState<CustomerDto | null>(null);
  const [newPassword, setNewPassword] = useState('');

  // State for Fetching
  const [pageIndex, setPageIndex] = useState(PaginationDefaults.PAGE_INDEX);
  const [pageSize, setPageSize] = useState(PaginationDefaults.PAGE_SIZE);
  const [sortField, setSortField] = useState('createdAt');
  const [sortDir, setSortDir] = useState<SortDirection>(SortDirection.DESC);
  const [filters, setFilters] = useState<Record<string, string>>({ role: 'customer' });

  // Fetch Data
  const { data: customerResponse, isLoading, refetch } = useQuery({
    queryKey: ['customers', pageIndex, pageSize, sortField, sortDir, filters],
    queryFn: () => customerService.search({
      pageIndex,
      pageSize,
      sortBy: sortField,
      sortDesc: sortDir === SortDirection.DESC,
      filters: Object.entries(filters).map(([field, value]) => ({ field, value })),
      search: filters.search,
      searchField: filters.search ? 'fullName' : undefined
    })
  });

  // Fetch Stats
  const { data: statsData, isLoading: isStatsLoading } = useQuery({
      queryKey: ['customer-stats'],
      queryFn: () => customerService.getStats(),
      staleTime: 60000, 
  });

  const stats: StatItem[] = [
      {
          label: t('admin.stats.totalCustomers'),
          value: statsData?.total || 0,
          icon: <Users size={24} />,
          color: 'blue',
          loading: isStatsLoading
      },
      {
          label: t('admin.stats.notActivated'),
          value: statsData?.unverified || 0,
          icon: <AlertTriangle size={24} />,
          color: 'rose',
          loading: isStatsLoading
      },
      {
          label: t('admin.stats.activeCustomers'),
          value: statsData?.active || 0,
          icon: <Users size={24} />,
          color: 'emerald',
          loading: isStatsLoading
      }
  ];

  const items = customerResponse?.data?.items || [];
  const totalCount = customerResponse?.data?.totalItems || PaginationDefaults.TOTAL_ITEMS;
  const totalPages = Math.ceil(totalCount / pageSize) || PaginationDefaults.TOTAL_PAGES;

  // Entity Manager
  const {
      isFormOpen,
      editingItem: editingCustomer,
      itemToDelete: customerToDelete,
      isLoading: isSubmitting,
      isDeleting,
      openCreate,
      openEdit,
      closeForm,
      confirmDelete,
      cancelDelete,
      create: createCustomer,
      update: updateCustomer,
      delete: deleteCustomer
  } = useEntityManager<CustomerDto, CreateCustomerRequest, UpdateCustomerRequest>({
    service: customerService,
    queryKey: ['customers', pageIndex, pageSize, sortField, sortDir, filters],
  });

  const toast = useToast();
  // Bulk Delete State
  const [itemsToDelete, setItemsToDelete] = useState<CustomerDto[] | null>(null);

  const bulkDeleteMutation = useMutation({
    mutationFn: (codes: string[]) => customerService.deleteMultiple(codes),
    onSuccess: () => {
      toast.success(t('common.deleteSuccess'));
      setItemsToDelete(null);
      refetch();
    },
    onError: (err: any) => {
      toast.error(err.message || t('common.deleteError'));
    }
  });

  const handleBulkDelete = (items: CustomerDto[]) => {
    setItemsToDelete(items);
  };

  const confirmBulkDelete = () => {
    if (itemsToDelete) {
      bulkDeleteMutation.mutate(itemsToDelete.map(i => i.code));
    }
  };

  // Form State
  const [formData, setFormData] = useState({
      username: '',
      email: '',
      password: '',
      fullName: '',
      phone: '',
      role: 'customer',
      isActive: true,
  });

  const resetForm = () => setFormData({
      username: '',
      email: '',
      password: '',
      fullName: '',
      phone: '',
      role: 'customer',
      isActive: true,
  });

  const handleOpenCreate = () => {
      resetForm();
      openCreate();
  };

  const handleOpenEdit = (customer: CustomerDto) => {
      setFormData({
          username: customer.username || '',
          email: customer.email,
          password: '',
          fullName: customer.fullName || '',
          phone: customer.phone || '',
          role: customer.role || 'customer',
          isActive: customer.isActive
      });
      openEdit(customer);
  };

  const handleSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      
      if (editingCustomer) {
          updateCustomer(editingCustomer.code, {
              fullName: formData.fullName,
              email: formData.email,
              phone: formData.phone,
              role: formData.role,
              isActive: formData.isActive,
              password: formData.password || undefined
          });
      } else {
          createCustomer({
              username: formData.username,
              email: formData.email,
              password: formData.password,
              fullName: formData.fullName,
              phone: formData.phone,
              role: formData.role,
              isActive: formData.isActive
          });
      }
  };

  const handleResetPasswordPrompt = (customer: CustomerDto) => {
      setResettingCustomer(customer);
      setNewPassword('');
  };

  const confirmResetPassword = async () => {
      if (!resettingCustomer || !newPassword) return;
      try {
          await customerService.update(resettingCustomer.code, { password: newPassword });
          toast.success(t('messages.saveSuccess'));
          setResettingCustomer(null);
      } catch (err) {
          toast.error(t('messages.error'));
      }
  };


  const columns: DataTableColumn<CustomerDto>[] = [
    {
      id: 'fullName',
      header: t('common.fields.customer'),
      accessor: (customer) => (
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-full bg-gradient-to-r from-blue-500 to-purple-500 flex items-center justify-center text-white font-bold shadow-sm">
            {customer.fullName?.charAt(0) || customer.username?.charAt(0)}
          </div>
          <div>
            <p className="font-medium text-slate-800 dark:text-slate-100">{customer.fullName || customer.username}</p>
            <p className="text-xs text-slate-500">{customer.username}</p>
          </div>
        </div>
      ),
      sortable: true
    },
    {
      id: 'contact',
      header: t('common.fields.contact'),
      accessor: (customer) => (
        <div className="space-y-1">
          <p className="text-sm flex items-center gap-2 text-slate-600 dark:text-slate-400">
            <Mail size={14} className="text-blue-400" />
            {customer.email}
          </p>
          {customer.phone && (
            <p className="text-sm flex items-center gap-2 text-slate-500 dark:text-slate-500">
              <Phone size={14} className="text-slate-400" />
              {customer.phone}
            </p>
          )}
        </div>
      )
    },
    {
      id: 'role',
      header: t('common.fields.role'),
      accessor: (customer) => (
        <Badge color={customer.role === 'admin' ? 'error' : 'info'}>
          {t(`admin.types.${customer.role.toLowerCase()}`, customer.role)}
        </Badge>
      ),
      className: 'text-center',
      headerClassName: 'text-center'
    },
    {
      id: 'isActive',
      header: t('common.fields.status'),
      accessor: (customer) => (
        <Badge color={customer.isActive ? 'success' : 'secondary'}>
          {customer.isActive ? t('admin.status.active') : t('admin.status.inactive')}
        </Badge>
      ),
      className: 'text-center',
      headerClassName: 'text-center'
    },
    {
      id: 'isEmailVerified',
      header: t('common.fields.emailVerified', 'Email Verified'),
      accessor: (customer) => (
        <Badge color={customer.isEmailVerified ? 'success' : 'error'} variant="outline">
          {customer.isEmailVerified ? t('admin.status.verified') : t('admin.status.unactivated')}
        </Badge>
      ),
      className: 'text-center',
      headerClassName: 'text-center'
    },
    {
      id: 'lastLogin',
      header: t('common.fields.lastLogin', 'Last Login'),
      accessor: (customer) => <span className="text-slate-500">{customer.lastLogin ? formatDate(customer.lastLogin) : t('common.never', 'Never')}</span>,
      sortable: true
    },
    {
      id: 'joinDate',
      header: t('common.fields.joinDate'),
      accessor: (customer) => <span className="text-slate-500">{formatDate(customer.createdAt)}</span>,
      sortable: true
    },

  ];

  const handleSort = (field: string, dir: 'asc' | 'desc') => {
    setSortField(field);
    setSortDir(dir as SortDirection);
  };

  const handleAdvancedSearch = (newFilters: Record<string, string>) => {
    setFilters(newFilters);
    setPageIndex(PaginationDefaults.PAGE_INDEX);
  };

  const handleReset = () => {
    // Reset to starting state: just customers sorted by createdAt desc
    setFilters({ role: 'customer' }); 
    setPageIndex(PaginationDefaults.PAGE_INDEX);
    setSortField('createdAt');
    setSortDir(SortDirection.DESC);
    refetch();
  };

  return (
    <div className="space-y-6">
      <AdminPageHeader
        title="admin.sidebar.customers"
        subtitle="admin.subtitles.customers"
      />

      <StatsCards stats={stats} />

      <DataTable
        columns={columns}
        data={items}
        keyField="code"
        isLoading={isLoading}
        onBulkDelete={handleBulkDelete}
        onView={(customer) => setSelectedCustomer(customer)}
        onEdit={handleOpenEdit}
        onDelete={confirmDelete}
        onAdd={handleOpenCreate}
        initialFilters={{ role: 'customer' }}
        renderRowActions={(customer) => (
            <button
              className="p-1.5 text-slate-500 hover:text-amber-600 hover:bg-amber-50 rounded transition-colors"
              title={t('admin.actions.resetPassword')}
              onClick={() => handleResetPasswordPrompt(customer)}
            >
              <Key size={18} />
            </button>
        )}

        // Sorting
        externalSortField={sortField}
        externalSortDir={sortDir}
        onExternalSort={handleSort}

        // Search & Filter
        onAdvancedSearch={handleAdvancedSearch}
        onReset={handleReset}
        advancedFilterDefs={[
          {
            id: 'fullName',
            label: t('common.fields.customer'),
            type: 'text',
            placeholder: t('common.placeholders.search')
          },
          {
            id: 'email',
            label: 'Email',
            type: 'text',
          },
          {
            id: 'phone',
            label: t('common.fields.phone'),
            type: 'text',
          },
          {
            id: 'role',
            label: t('common.fields.role'),
            type: 'select',
            options: [
              { value: 'customer', label: t('admin.types.customer') },
              { value: 'admin', label: t('admin.types.admin') },
              { value: 'staff', label: t('admin.types.staff') }
            ]
          }
        ]}

        // Pagination
        currentPage={pageIndex}
        totalItems={totalCount}
        totalPages={totalPages}
        pageSize={pageSize}
        onPageChange={setPageIndex}
        onPageSizeChange={(size) => {
          setPageSize(size);
          setPageIndex(PaginationDefaults.PAGE_INDEX);
        }}

        // Visibility
        enableColumnVisibility={true}
        exportFilename="customers_export"
        onExportAllData={async () => {
          const response = await customerService.search({ pageIndex: 1, pageSize: 10000 });
          return (response.data?.items || []) as unknown as CustomerDto[];
        }}
        emptyMessage={t('common.noResults')}
      />

      {/* Customer Detail Modal */}
      <Modal
        isOpen={!!selectedCustomer}
        onClose={() => setSelectedCustomer(null)}
        title={t('admin.actions.view') + ' ' + t('common.fields.customer')}
        size="md"
      >
        {selectedCustomer && (
          <div className="space-y-6">
            <div className="flex items-center gap-4">
              <div className="w-16 h-16 rounded-full bg-gradient-to-r from-blue-500 to-purple-500 flex items-center justify-center text-white font-bold text-2xl shadow-md">
                {selectedCustomer.fullName?.charAt(0) || selectedCustomer.username?.charAt(0)}
              </div>
              <div>
                <h2 className="text-xl font-bold text-slate-800 dark:text-white">{selectedCustomer.fullName}</h2>
                <p className="text-slate-500">{selectedCustomer.email}</p>
                <div className="flex items-center gap-2 mt-1">
                    <Badge color={selectedCustomer.isActive ? 'success' : 'secondary'}>
                    {selectedCustomer.isActive ? t('admin.status.active') : t('admin.status.inactive')}
                    </Badge>
                     <Badge color={selectedCustomer.role === 'admin' ? 'error' : 'info'}>{selectedCustomer.role}</Badge>
                </div>
              </div>
            </div>

            <div className="space-y-3">
              <h3 className="font-semibold text-slate-800 dark:text-white">{t('common.fields.contact')}</h3>
              <div className="space-y-2 text-slate-600 dark:text-slate-400">
                <p className="flex items-center gap-2">
                  <Mail size={16} className="text-blue-500" />
                  {selectedCustomer.email}
                </p>
                {selectedCustomer.phone && (
                  <p className="flex items-center gap-2">
                    <Phone size={16} className="text-slate-400" />
                    {selectedCustomer.phone}
                  </p>
                )}
                <p className="flex items-center gap-2">
                  <span className="font-semibold w-24">{t('common.fields.username')}:</span>
                  {selectedCustomer.username}
                </p>
                <p className="flex items-center gap-2">
                  <span className="font-semibold w-24">{t('common.fields.address')}:</span>
                  {selectedCustomer.address ? `${selectedCustomer.address}, ${selectedCustomer.ward}, ${selectedCustomer.district}, ${selectedCustomer.city}` : t('common.actions.none')}
                </p>
              </div>
            </div>

            <div className="flex gap-3">
              <Button fullWidth>
                {t('common.fields.email')}
              </Button>
            </div>
             <div className="flex justify-end pt-4">
              <Button onClick={() => setSelectedCustomer(null)} variant="outline">
                {t('common.close')}
              </Button>
            </div>
          </div>
        )}
      </Modal>


      {/* Customer Create/Edit Modal */}
      <Modal
        isOpen={isFormOpen}
        onClose={closeForm}
        title={editingCustomer ? t('admin.actions.edit') + ' ' + t('common.fields.customer') : t('admin.actions.create') + ' ' + t('common.fields.customer')}
        size="lg"
      >
        <form onSubmit={handleSubmit} className="space-y-4">
            {!editingCustomer && (
                <Input
                    label={t('common.fields.username')}
                    value={formData.username}
                    onChange={e => setFormData({...formData, username: e.target.value})}
                    isRequired
                    placeholder={t('common.placeholders.enterName')}
                />
            )}
            
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                 <Input
                    label={t('common.fields.customer')}
                    value={formData.fullName}
                    onChange={e => setFormData({...formData, fullName: e.target.value})}
                    placeholder={t('common.placeholders.enterName')}
                />
                 <Input
                    label={t('common.fields.email')}
                    type="email"
                    value={formData.email}
                    onChange={e => setFormData({...formData, email: e.target.value})}
                    isRequired
                    placeholder="example@email.com"
                />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                 <Input
                    label={t('common.fields.phone')}
                    value={formData.phone}
                    onChange={e => setFormData({...formData, phone: e.target.value})}
                    placeholder={t('common.placeholders.enterPhone')}
                />
                 <Select
                    label={t('common.fields.role')}
                    value={formData.role}
                    onChange={e => setFormData({...formData, role: e.target.value})}
                    options={[
                        { value: 'customer', label: t('admin.types.customer') },
                        { value: 'admin', label: t('admin.types.admin') },
                        { value: 'staff', label: t('admin.types.staff') }
                    ]}
                />
            </div>

             <Input
                label={editingCustomer ? t('common.fields.newPassword') : t('common.fields.password')}
                type="password"
                value={formData.password}
                onChange={e => setFormData({...formData, password: e.target.value})}
                isRequired={!editingCustomer}
                placeholder={editingCustomer ? t('common.hints.leaveBlankKeepCurrent') : t('common.placeholders.enterPassword')}
            />

                <div className="p-4 bg-gray-50 dark:bg-slate-800/50 rounded-lg">
                     <Switch
                        label={t('common.fields.status')}
                        description={t('admin.statusHint', 'Bật để tài khoản hoạt động')}
                        checked={formData.isActive}
                        onChange={(checked) => setFormData({...formData, isActive: checked})}
                     />
                </div>

            <div className="flex justify-end gap-3 pt-4">
                <Button type="button" variant="outline" onClick={closeForm}>
                    {t('common.cancel')}
                </Button>
                <Button type="submit" isLoading={isSubmitting}>
                    {editingCustomer ? t('common.save') : t('common.create')}
                </Button>
            </div>
        </form>
      </Modal>

      {/* Delete Confirmation */}
      <ConfirmDialog
        isOpen={!!customerToDelete}
        onClose={cancelDelete}
        title={t('admin.actions.delete')}
        message={t('messages.confirmDelete')}
        confirmText={t('common.delete')}
        onConfirm={() => customerToDelete && deleteCustomer(customerToDelete.code)}
        isLoading={isDeleting}
      />
      
      {/* Bulk Delete Confirmation */}
      <ConfirmDialog
        isOpen={!!itemsToDelete}
        onClose={() => setItemsToDelete(null)}
        onConfirm={confirmBulkDelete}
        title={t('admin.actions.delete')}
        message={t('common.confirmDelete', { count: itemsToDelete?.length || 0 })}
        confirmText={t('common.delete')}
        isLoading={bulkDeleteMutation.isPending}
      />

      <Modal
        isOpen={!!resettingCustomer}
        onClose={() => setResettingCustomer(null)}
        title={t('admin.actions.resetPasswordTitle', { name: resettingCustomer?.fullName || resettingCustomer?.username })}
        size="sm"
      >
        <div className="space-y-4">
            <Input
                label={t('common.fields.newPassword')}
                type="password"
                value={newPassword}
                onChange={e => setNewPassword(e.target.value)}
                placeholder={t('common.placeholders.enterPassword')}
                isRequired
            />
            <div className="flex justify-end gap-3">
                <Button variant="outline" onClick={() => setResettingCustomer(null)}>{t('common.cancel')}</Button>
                <Button onClick={confirmResetPassword} disabled={!newPassword}>{t('common.update')}</Button>
            </div>
        </div>
      </Modal>
    </div>
  );
};

export default CustomersPage;

import { useTranslation } from 'react-i18next';
import { motion } from 'framer-motion';
import {
  DollarSign,
  ShoppingBag,
  Users,
  Package,
  TrendingUp,
  TrendingDown,
  ArrowUpRight,
  FileText,
  Loader2,
} from 'lucide-react';
import { RevenueChart, AdminPageHeader } from '@/components/admin';
import { formatCurrency, getStatusColor, getStatusText } from '@/utils/format';
import { dashboardService } from '@/services';
import { useQuery } from '@tanstack/react-query';
import { useAdminOrders } from '@/hooks';
import { PageSize, PaginationDefaults } from '@/constants';

// ============ Stat Card Component ============
interface StatCardProps {
  title: string;
  value: string | number;
  change?: number;
  icon: React.ElementType;
  color: string;
}

const StatCard = ({ title, value, change, icon: Icon, color }: StatCardProps) => {
  const { t } = useTranslation();
  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className="bg-primary rounded-xl p-6"
    >
      <div className="flex items-start justify-between">
        <div>
          <p className="text-sm text-secondary mb-1">{title}</p>
          <p className="text-2xl font-bold">{value}</p>
          {typeof change === 'number' && (
            <p className={`flex items-center gap-1 text-sm mt-2 ${change >= 0 ? 'text-success' : 'text-error'}`}>
              {change >= 0 ? <TrendingUp size={14} /> : <TrendingDown size={14} />}
              {change >= 0 ? '+' : ''}{change}% {t('admin.stats.vsLastMonth')}
            </p>
          )}
        </div>
        <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${color}`}>
          <Icon size={24} className="text-white" />
        </div>
      </div>
    </motion.div>
  );
};

// ============ Dashboard Page ============
export const DashboardPage = () => {
  const { t, i18n } = useTranslation();



  // Fetch recent orders
  const { data: ordersData, isLoading: ordersLoading } = useAdminOrders({ pageIndex: PaginationDefaults.PAGE_INDEX, pageSize: PageSize.SMALL });
  const recentOrders = ordersData?.orders || [];

  const { data: statsResponse, isLoading: statsLoading, isError: statsError, refetch } = useQuery({
    queryKey: ['dashboard-stats'],
    queryFn: () => dashboardService.getStats(),
    staleTime: 30000,
  });

  const stats = statsResponse?.success && statsResponse?.data ? statsResponse.data : {
    totalRevenue: 0,
    revenueChange: 0,
    totalOrders: 0,
    ordersChange: 0,
    totalCustomers: 0,
    customersChange: 0,
    totalProducts: 0,
    pendingQuotes: 0
  };

  return (
    <div className="space-y-6">
      <AdminPageHeader
        title="admin.sidebar.dashboard"
        subtitle="admin.subtitles.dashboard"
        rightSection={
          <div className="flex items-center gap-3">
            <p className="text-secondary font-medium hidden sm:block">
              {new Date().toLocaleDateString(i18n.language, { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
            </p>
            <button
              onClick={() => refetch()}
              disabled={statsLoading}
              className="p-2 hover:bg-secondary rounded-lg transition-colors text-primary"
              title={t('common.refresh')}
            >
              <Loader2 size={20} className={statsLoading ? 'animate-spin' : ''} />
            </button>
          </div>
        }
      />

      {/* Stats Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        {statsLoading ? (
           Array(4).fill(0).map((_, i) => (
             <div key={i} className="bg-primary rounded-xl p-6 h-32 animate-pulse" />
           ))
        ) : statsError ? (
           <div className="col-span-4 p-4 bg-red-50 text-red-500 rounded-xl">
             Failed to load dashboard statistics. Please try again.
           </div>
        ) : (
          <>
            <StatCard
              title={t('admin.stats.revenue')}
              value={formatCurrency(stats.totalRevenue)}
              change={stats.revenueChange}
              icon={DollarSign}
              color="bg-gradient-to-r from-green-500 to-emerald-500"
            />
            <StatCard
              title={t('admin.stats.orders')}
              value={stats.totalOrders.toLocaleString()}
              change={stats.ordersChange}
              icon={ShoppingBag}
              color="bg-gradient-to-r from-blue-500 to-cyan-500"
            />
            <StatCard
              title={t('admin.stats.customers')}
              value={stats.totalCustomers.toLocaleString()}
              change={stats.customersChange}
              icon={Users}
              color="bg-gradient-to-r from-purple-500 to-pink-500"
            />
            <StatCard
              title={t('admin.stats.products')}
              value={stats.totalProducts}
              icon={Package}
              color="bg-gradient-to-r from-orange-500 to-amber-500"
            />
          </>
        )}
      </div>

      {/* Charts & Tables Row */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Revenue Chart */}
        <div className="lg:col-span-2 bg-primary rounded-xl p-6 shadow-sm border">
          <h2 className="font-bold mb-4">{t('admin.revenueChart')}</h2>
          <div className="h-64">
            <RevenueChart data={stats.revenueChart} />
          </div>
        </div>

        {/* Top Products */}
        <div className="bg-primary rounded-xl p-6">
          <h2 className="font-bold mb-4">{t('admin.topProducts')}</h2>
          <div className="space-y-4">
            {(stats.topProducts || []).length === 0 ? (
                 <p className="text-secondary text-sm">{t('common.noData')}</p>
            ) : (stats.topProducts || []).map((product, index) => (
              <div key={index} className="flex items-center gap-3">
                <span className="w-8 h-8 rounded-lg bg-secondary flex items-center justify-center font-bold text-sm">
                  {index + 1}
                </span>
                <div className="flex-1 min-w-0">
                  <p className="font-medium truncate">{product.name}</p>
                  <p className="text-sm text-tertiary">{product.sales} {t('admin.sold')}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Recent Orders & Pending Quotes */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Recent Orders */}
        <div className="bg-primary rounded-xl p-6">
          <div className="flex items-center justify-between mb-4">
            <h2 className="font-bold">{t('admin.recentOrders')}</h2>
            <a href="/admin/orders" className="text-sm text-primary flex items-center gap-1 hover:underline">
              {t('common.viewAll')} <ArrowUpRight size={14} />
            </a>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="text-left text-sm text-tertiary border-b">
                  <th className="pb-3">{t('common.fields.orderCode')}</th>
                  <th className="pb-3">{t('common.fields.customer')}</th>
                  <th className="pb-3">{t('common.fields.total')}</th>
                  <th className="pb-3">{t('common.fields.status')}</th>
                </tr>
              </thead>
              <tbody>
                {ordersLoading ? (
                  <tr><td colSpan={4} className="py-8 text-center"><Loader2 className="animate-spin mx-auto" /></td></tr>
                ) : recentOrders.length === 0 ? (
                  <tr><td colSpan={4} className="py-4 text-center text-secondary">{t('common.noData')}</td></tr>
                ) : (recentOrders.map((order) => (
                  <tr key={order.code} className="border-b last:border-0">
                    <td className="py-3 font-medium">{order.code}</td>
                    <td className="py-3">{order.shippingName || order.userCode}</td>
                    <td className="py-3 text-error font-medium">{formatCurrency(order.finalAmount)}</td>
                    <td className="py-3">
                      <span className={`px-2 py-1 rounded-full text-xs font-medium bg-${getStatusColor(order.status)}/20 text-${getStatusColor(order.status)}`}>
                        {t(getStatusText(order.status))}
                      </span>
                    </td>
                  </tr>
                )))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Pending Quotes (Note: Currently we only show count, list is dummy or requires real fetch) */}
        <div className="bg-primary rounded-xl p-6">
          <div className="flex items-center justify-between mb-4">
            <h2 className="font-bold flex items-center gap-2">
              {t('admin.quoteRequests')}
              <span className="px-2 py-0.5 bg-error/20 text-error text-xs rounded-full">
                {stats.pendingQuotes} {t('admin.pending')}
              </span>
            </h2>
            <a href="/admin/quotes" className="text-sm text-primary flex items-center gap-1 hover:underline">
              {t('common.viewAll')} <ArrowUpRight size={14} />
            </a>
          </div>
          <p className="text-sm text-secondary">
             {t('common.messages.checkQuotesPage')}
          </p>
        </div>
      </div>
    </div>
  );
};

export default DashboardPage;

/* eslint-disable @typescript-eslint/no-explicit-any */
import { useState, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { FileText, Plus, Search, Trash2, Edit, Eye, Image as ImageIcon, Globe } from 'lucide-react';
import { Button, Badge, Modal, ConfirmDialog } from '@/components/ui';
import { AdminPageHeader } from '@/components/admin';
import { DataTable } from '@/components/common';
import { formatDate } from '@/utils/format';
import { newsService, type NewsDto } from '@/services/newsService';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { PaginationDefaults } from '@/constants';
import { useToast } from '@/store';

export const NewsPage = () => {
  const { t } = useTranslation();
  const { success, error: toastError } = useToast();
  const queryClient = useQueryClient();

  // State
  const [currentPage, setCurrentPage] = useState(PaginationDefaults.PAGE_INDEX);
  const [pageSize, setPageSize] = useState(PaginationDefaults.PAGE_SIZE);
  const [searchQuery, setSearchQuery] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingNews, setEditingNews] = useState<NewsDto | null>(null);
  const [newsToDelete, setNewsToDelete] = useState<NewsDto | null>(null);
  const [activeTab, setActiveTab ] = useState<'content' | 'seo'>('content');

  // Form State
  const [formData, setFormData] = useState({
    title: '',
    summary: '',
    content: '',
    thumbnail: '',
    author: '',
    isActive: true,
    metaTitle: '',
    metaDescription: '',
    metaKeywords: '',
    slug: ''
  });

  // Queries
  const { data: newsData, isLoading, isFetching } = useQuery({
    queryKey: ['admin-news', currentPage, pageSize, searchQuery],
    queryFn: () => newsService.search({
      pageIndex: currentPage,
      pageSize: pageSize,
      search: searchQuery
    }),
  });

  const newsItems = newsData?.data?.items || [];
  const totalPages = newsData?.data?.totalPages || 1;

  // Mutations
  const createMutation = useMutation({
    mutationFn: (data: any) => newsService.create(data),
    onSuccess: () => {
      success(t('messages.createSuccess'));
      queryClient.invalidateQueries({ queryKey: ['admin-news'] });
      setIsModalOpen(false);
      resetForm();
    },
    onError: (err: any) => toastError(err.message || t('messages.createError'))
  });

  const updateMutation = useMutation({
    mutationFn: ({ code, data }: { code: string, data: any }) => newsService.update(code, data),
    onSuccess: () => {
      success(t('messages.updateSuccess'));
      queryClient.invalidateQueries({ queryKey: ['admin-news'] });
      setIsModalOpen(false);
      resetForm();
    },
    onError: (err: any) => toastError(err.message || t('messages.updateError'))
  });

  const deleteMutation = useMutation({
    mutationFn: (code: string) => newsService.delete(code),
    onSuccess: () => {
      success(t('messages.deleteSuccess'));
      queryClient.invalidateQueries({ queryKey: ['admin-news'] });
      setNewsToDelete(null);
    },
    onError: () => toastError(t('messages.deleteError'))
  });

  // Handlers
  const resetForm = () => {
    setFormData({
      title: '',
      summary: '',
      content: '',
      thumbnail: '',
      author: '',
      isActive: true,
      metaTitle: '',
      metaDescription: '',
      metaKeywords: '',
      slug: ''
    });
    setEditingNews(null);
    setActiveTab('content');
  };

  const handleEdit = (item: NewsDto) => {
    setEditingNews(item);
    setFormData({
      title: item.title,
      summary: item.summary || '',
      content: item.content || '',
      thumbnail: item.thumbnail || '',
      author: item.author || '',
      isActive: item.isActive,
      metaTitle: item.metaTitle || '',
      metaDescription: item.metaDescription || '',
      metaKeywords: item.metaKeywords || '',
      slug: item.slug || ''
    });
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingNews) {
      updateMutation.mutate({ code: editingNews.code, data: formData });
    } else {
      createMutation.mutate(formData);
    }
  };

  // Columns
  const columns = [
    {
      id: 'thumbnail',
      header: '',
      accessor: (row: NewsDto) => (
        <div className="w-12 h-12 rounded bg-tertiary flex items-center justify-center overflow-hidden">
          {row.thumbnail ? (
            <img src={row.thumbnail} alt={row.title} className="w-full h-full object-cover" />
          ) : (
            <ImageIcon size={20} className="text-tertiary" />
          )}
        </div>
      ),
      className: 'w-16'
    },
    {
      id: 'title',
      header: t('common.fields.title'),
      accessor: (row: NewsDto) => (
        <div className="max-w-[300px]">
          <p className="font-medium truncate">{row.title}</p>
          <p className="text-xs text-tertiary truncate">{row.summary}</p>
        </div>
      )
    },
    {
       id: 'author',
       header: t('common.fields.author'),
       accessor: (row: NewsDto) => row.author || t('common.none')
    },
    {
      id: 'status',
      header: t('common.fields.status'),
      accessor: (row: NewsDto) => (
        <Badge color={row.isActive ? 'success' : 'error'} size="sm">
          {row.isActive ? t('admin.status.published') : t('admin.status.draft')}
        </Badge>
      ),
      className: 'text-center'
    },
    {
      id: 'date',
      header: t('common.fields.date'),
      accessor: (row: NewsDto) => <span className="text-secondary text-sm">{formatDate(row.publishedAt || row.createdAt)}</span>
    }
  ];

  return (
    <div className="space-y-6">
      <AdminPageHeader
        title="admin.sidebar.news"
        subtitle="admin.subtitles.news"
        rightSection={
          <Button leftIcon={<Plus size={18} />} onClick={() => { resetForm(); setIsModalOpen(true); }}>
            {t('admin.news.add')}
          </Button>
        }
      />

      {/* Toolbar */}
      <div className="flex flex-col sm:flex-row gap-4 justify-between bg-primary p-4 rounded-xl border border-tertiary">
        <div className="relative flex-1 max-w-md">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-tertiary" size={18} />
          <input
            type="text"
            placeholder={t('common.placeholders.search')}
            className="w-full pl-10 pr-4 py-2 bg-secondary border border-tertiary rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/20"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </div>
      </div>

      <DataTable
        columns={columns}
        data={newsItems}
        isLoading={isLoading || isFetching}
        keyField="code"
        
        currentPage={currentPage}
        totalPages={totalPages}
        pageSize={pageSize}
        onPageChange={setCurrentPage}
        onPageSizeChange={setPageSize}

        renderRowActions={(row) => (
          <div className="flex items-center gap-1">
            <button
              className="p-1.5 hover:bg-primary/10 rounded text-primary"
              title={t('common.actions.edit')}
              onClick={() => handleEdit(row)}
            >
              <Edit size={18} />
            </button>
            <button
              className="p-1.5 hover:bg-error/10 rounded text-error"
              title={t('common.actions.delete')}
              onClick={() => setNewsToDelete(row)}
            >
              <Trash2 size={18} />
            </button>
          </div>
        )}
      />

      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={editingNews ? t('admin.news.edit') : t('admin.news.add')}
        size="xl"
        footer={
          <div className="flex justify-end gap-2">
             <Button variant="outline" onClick={() => setIsModalOpen(false)}>{t('common.cancel')}</Button>
             <Button onClick={handleSubmit} isLoading={createMutation.isPending || updateMutation.isPending}>{t('common.save')}</Button>
          </div>
        }
      >
        <div className="space-y-4">
           {/* Tabs */}
           <div className="flex border-b border-tertiary">
              <button 
                className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${activeTab === 'content' ? 'border-primary text-primary' : 'border-transparent text-tertiary'}`}
                onClick={() => setActiveTab('content')}
              >
                {t('admin.news.contentTab')}
              </button>
              <button 
                className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${activeTab === 'seo' ? 'border-primary text-primary' : 'border-transparent text-tertiary'}`}
                onClick={() => setActiveTab('seo')}
              >
                {t('admin.news.seoTab')}
              </button>
           </div>

           <form onSubmit={handleSubmit} className="space-y-4">
             {activeTab === 'content' ? (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="md:col-span-2">
                    <label className="block text-sm font-medium mb-1">{t('common.fields.title')} <span className="text-error">*</span></label>
                    <input
                      type="text"
                      className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                      value={formData.title}
                      onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                      required
                    />
                  </div>
                  
                  <div>
                    <label className="block text-sm font-medium mb-1">{t('common.fields.author')}</label>
                    <input
                      type="text"
                      className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                      value={formData.author}
                      onChange={(e) => setFormData({ ...formData, author: e.target.value })}
                    />
                  </div>

                  <div>
                     <label className="block text-sm font-medium mb-1">{t('admin.news.thumbnailUrl')}</label>
                     <input
                        type="text"
                        className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                        value={formData.thumbnail}
                        onChange={(e) => setFormData({ ...formData, thumbnail: e.target.value })}
                        placeholder="https://..."
                     />
                  </div>

                  <div className="md:col-span-2">
                    <label className="block text-sm font-medium mb-1">{t('admin.news.summary')}</label>
                    <textarea
                      className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20 h-20"
                      value={formData.summary}
                      onChange={(e) => setFormData({ ...formData, summary: e.target.value })}
                    />
                  </div>

                  <div className="md:col-span-2">
                    <label className="block text-sm font-medium mb-1">{t('admin.news.content')} <span className="text-error">*</span></label>
                    <textarea
                      className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20 h-64 font-mono text-sm"
                      value={formData.content}
                      onChange={(e) => setFormData({ ...formData, content: e.target.value })}
                      required
                    />
                  </div>

                  <div className="flex items-center gap-2">
                    <input
                      type="checkbox"
                      id="isActive"
                      className="w-4 h-4 rounded border-tertiary"
                      checked={formData.isActive}
                      onChange={(e) => setFormData({ ...formData, isActive: e.target.checked })}
                    />
                    <label htmlFor="isActive" className="text-sm font-medium cursor-pointer">{t('admin.status.published')}</label>
                  </div>
                </div>
             ) : (
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium mb-1">{t('admin.news.slug')}</label>
                    <input
                      type="text"
                      className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                      value={formData.slug}
                      onChange={(e) => setFormData({ ...formData, slug: e.target.value.toLowerCase().replace(/\s+/g, '-') })}
                      placeholder="post-title-slug"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">{t('admin.news.metaTitle')}</label>
                    <input
                      type="text"
                      className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                      value={formData.metaTitle}
                      onChange={(e) => setFormData({ ...formData, metaTitle: e.target.value })}
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">{t('admin.news.metaDescription')}</label>
                    <textarea
                      className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20 h-24"
                      value={formData.metaDescription}
                      onChange={(e) => setFormData({ ...formData, metaDescription: e.target.value })}
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium mb-1">{t('admin.news.metaKeywords')}</label>
                    <input
                      type="text"
                      className="w-full p-2 bg-secondary border border-tertiary rounded-lg outline-none focus:ring-2 focus:ring-primary/20"
                      value={formData.metaKeywords}
                      onChange={(e) => setFormData({ ...formData, metaKeywords: e.target.value })}
                      placeholder="news, shop, organic"
                    />
                  </div>
                </div>
             )}
           </form>
        </div>
      </Modal>

      <ConfirmDialog
        isOpen={!!newsToDelete}
        onClose={() => setNewsToDelete(null)}
        onConfirm={() => newsToDelete && deleteMutation.mutate(newsToDelete.code)}
        title={t('common.actions.delete')}
        message={t('messages.confirmDelete')}
        variant="danger"
        isLoading={deleteMutation.isPending}
      />
    </div>
  );
};

export default NewsPage;

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Truck, Package, ClipboardList, Check, X, Printer } from 'lucide-react';
import defaultImage from '@/assets/default-image.png';
import { Button, Badge, Modal, ConfirmDialog } from '@/components/ui';
import { useAdminOrders, useUpdateOrderStatus } from '@/hooks';
import { formatCurrency, formatDate, getStatusColor, getStatusText } from '@/utils/format';
import { orderService, type OrderDto } from '@/services/orderService';
import { AdminPageHeader } from '@/components/admin';
import { DataTable } from '@/components/common';
import { DataTableColumn } from '@/components/common/DataTable';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { PaginationDefaults } from '@/constants';
import { StatsCards } from '@/components/admin/StatsCards';
import { useQuery } from '@tanstack/react-query';

export const OrdersPage = () => {
  const { t } = useTranslation();
  const updateStatusMutation = useUpdateOrderStatus();

  // State
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedOrder, setSelectedOrder] = useState<OrderDto | null>(null);
  const [currentPage, setCurrentPage] = useState(PaginationDefaults.PAGE_INDEX);
  const [pageSize, setPageSize] = useState(PaginationDefaults.PAGE_SIZE);
  const [advancedFilters, setAdvancedFilters] = useState<Record<string, string>>({});



  const queryClient = useQueryClient();
  const [orderToDelete, setOrderToDelete] = useState<OrderDto | null>(null);

  const deleteMutation = useMutation({
    mutationFn: (id: string) => orderService.delete(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['admin-orders'] }); // adapt key if needed
      setOrderToDelete(null);
    }
  });

  const handleDelete = () => {
    if (orderToDelete) {
      deleteMutation.mutate(orderToDelete.code);
    }
  };

  // Actions
  const updateStatus = (orderId: string, newStatus: string) => {
    updateStatusMutation.mutate({ code: orderId, status: newStatus });
    if (selectedOrder && selectedOrder.code === orderId) {
      setSelectedOrder({ ...selectedOrder, status: newStatus });
    }
  };

  const handlePrintInvoice = () => {
    window.print();
  };

  // Column Definitions
  const columns: DataTableColumn<OrderDto>[] = [
    {
      id: 'code',
      header: t('common.fields.orderCode'),
      accessor: (row) => <span className="font-medium">{row.code}</span>,
      sortable: true
    },
    {
      id: 'customer',
      header: t('common.fields.customer'),
      accessor: (row) => (
        <div>
          <p className="font-medium">{row.shippingName || row.userCode}</p>
          <p className="text-xs text-tertiary">{row.shippingPhone || '-'}</p>
        </div>
      )
    },
    {
      id: 'products',
      header: t('admin.products'),
      accessor: (row) => <span>{t('admin.order.productCount', { count: row.orderItems?.length || 0 })}</span>,
      className: 'text-center',
      headerClassName: 'text-center'
    },
    {
      id: 'total',
      header: t('common.fields.total'),
      accessor: (row) => <span className="font-semibold text-error">{formatCurrency(row.finalAmount)}</span>,
      className: 'text-right',
      headerClassName: 'text-right',
      sortable: true
    },
    {
      id: 'payment',
      header: t('common.fields.payment'),
      accessor: (row) => (
        <Badge
          color={row.paymentStatus === 'paid' ? 'success' : row.paymentStatus === 'pending' ? 'warning' : 'error'}
          size="sm"
        >
          {row.paymentStatus === 'paid' ? t('admin.payment.paid') : row.paymentStatus === 'pending' ? t('admin.payment.pending') : t('admin.payment.failed')}
        </Badge>
      ),
      className: 'text-center',
      headerClassName: 'text-center'
    },
    {
      id: 'status',
      header: t('common.fields.status'),
      accessor: (row) => (
        <Badge color={getStatusColor(row.status) as "success" | "warning" | "error" | "info" | "primary" | "secondary"} size="sm">
          {t(getStatusText(row.status))}
        </Badge>
      ),
      className: 'text-center',
      headerClassName: 'text-center',
      sortable: true
    },
    {
      id: 'date',
      header: t('common.fields.date'),
      accessor: (row) => <span className="text-secondary text-sm">{formatDate(row.orderDate)}</span>,
      sortable: true
    }
  ];

  // Visible Columns State
  const [visibleColumns, setVisibleColumns] = useState<string[]>(columns.map(c => c.id));

  // Fetch Data
  const { data: ordersData, isLoading, isFetching, refetch } = useAdminOrders({
    pageIndex: currentPage,
    pageSize: pageSize,
    filters: {
      ...advancedFilters,
      ...(searchQuery ? { search: searchQuery } : {})
    }
  });

  const orders = ordersData?.orders || [];
  const totalPages = ordersData?.totalPages || 1;

  // Fetch Stats
  const { data: statsData, isLoading: isStatsLoading } = useQuery({
      queryKey: ['order-stats'],
      queryFn: () => orderService.getStats(),
      staleTime: 60000,
  });

  const handleAdvancedSearch = (filters: Record<string, string>) => {
    setAdvancedFilters(filters);
    setCurrentPage(PaginationDefaults.PAGE_INDEX);
  };

  const handleReset = () => {
    setAdvancedFilters({});
    setSearchQuery('');
    setCurrentPage(PaginationDefaults.PAGE_INDEX);
    setPageSize(PaginationDefaults.PAGE_SIZE);

  };

  // Selection & Toolbar State




  return (
    <div className="space-y-6">
      {/* Header */}
      <AdminPageHeader
        title="admin.sidebar.orders"
        subtitle="admin.subtitles.orders"
        rightSection={
          <div className="flex items-center gap-2">
            <Badge color="warning">{t('admin.order.pendingCount', { count: orders.filter(o => o.status === 'pending').length })}</Badge>
            <Badge color="info">{t('admin.order.shippingCount', { count: orders.filter(o => o.status === 'shipping').length })}</Badge>
          </div>
        }
      />

    <StatsCards stats={[
        {
            label: t('admin.stats.totalOrders'),
            value: statsData?.total || 0,
            icon: <ClipboardList size={24} />,
            color: 'blue',
            loading: isStatsLoading
        },
        {
            label: t('admin.stats.pendingOrders'),
            value: statsData?.pending || 0,
            icon: <Package size={24} />,
            color: 'amber',
            loading: isStatsLoading
        },
        {
            label: t('admin.stats.shippingOrders'),
            value: statsData?.shipping || 0,
            icon: <Truck size={24} />,
            color: 'purple',
            loading: isStatsLoading
        }
    ]} />

      <DataTable
        columns={columns}
        data={orders}
        keyField="code"
        isLoading={isLoading || isFetching}
        
        // Pagination
        currentPage={currentPage}
        totalPages={totalPages}
        pageSize={pageSize}
        onPageChange={setCurrentPage}
        onPageSizeChange={(size) => {
          setPageSize(size);
          setCurrentPage(PaginationDefaults.PAGE_INDEX);
        }}
        
        onAdd={() => { }} // Placeholder
        onView={(order) => setSelectedOrder(order)}
        onEdit={(order) => setSelectedOrder(order)} // Map Edit to View for now as Order Edit is complex
        onDelete={(order) => setOrderToDelete(order)}
        renderRowActions={(order) => (
          <>
            {order.status === 'pending' && (
              <button
                className="p-1.5 hover:bg-success/10 rounded transition-colors text-success"
                title={t('admin.actions.confirmOrder')}
                onClick={() => updateStatus(order.code, 'confirmed')}
              >
                <Check size={18} />
              </button>
            )}
  
            {order.status === 'confirmed' && (
              <button
                className="p-1.5 hover:bg-primary/10 rounded transition-colors text-primary"
                title={t('admin.actions.shipOrder')}
                onClick={() => updateStatus(order.code, 'shipping')}
              >
                <Truck size={18} />
              </button>
            )}
  
            {order.status === 'shipping' && (
              <button
                className="p-1.5 hover:bg-success/10 rounded transition-colors text-success"
                title={t('admin.actions.markDelivered')}
                onClick={() => updateStatus(order.code, 'delivered')}
              >
                <Package size={18} />
              </button>
            )}
  
            {order.status === 'delivered' && (
              <button
                className="p-1.5 hover:bg-secondary rounded transition-colors text-secondary"
                title={t('admin.actions.printInvoice')}
                onClick={handlePrintInvoice}
              >
                <Printer size={18} />
              </button>
            )}
  
            {order.status === 'pending' && (
              <button
                className="p-1.5 hover:bg-error/10 rounded transition-colors text-error"
                title={t('admin.actions.cancelOrder')}
                onClick={() => updateStatus(order.code, 'cancelled')}
              >
                <X size={18} />
              </button>
            )}
          </>
        )}
        onReset={handleReset}
        exportFilename="orders_export"
        exportColumns={[
          { key: 'code', label: t('common.fields.orderCode'), width: 15 },
          { key: 'shippingName', label: t('common.fields.customer'), width: 20 },
          { key: 'shippingPhone', label: t('common.fields.phone'), width: 15 },
          { key: 'shippingAddress', label: t('common.fields.address'), width: 30 },
          { key: 'totalAmount', label: t('common.fields.total'), width: 15 },
          { key: 'finalAmount', label: t('common.fields.finalAmount'), width: 15 },
          { key: 'shippingFee', label: t('common.fields.shippingFee'), width: 12 },
          { key: 'discountAmount', label: t('common.fields.discount'), width: 12 },
          { key: 'status', label: t('common.fields.status'), width: 15 },
          { key: 'paymentMethod', label: t('common.fields.paymentMethod'), width: 18 },
          { key: 'paymentStatus', label: t('common.fields.payment'), width: 15 },
          { key: 'orderDate', label: t('common.fields.date'), width: 18 },
          { key: 'note', label: t('common.fields.note'), width: 25 },
        ]}
        onExportAllData={async () => {
          const response = await orderService.search({ pageIndex: 1, pageSize: 10000 });
          return response.data?.items || [];
        }}
        enableSelection={false}

        // Search & Filter
        onAdvancedSearch={handleAdvancedSearch}
        advancedFilterDefs={[
          {
            id: 'fromDate',
            label: t('admin.filters.fromDate'),
            type: 'date',
            placeholder: 'dd/mm/yyyy'
          },
          {
            id: 'toDate',
            label: t('admin.filters.toDate'),
            type: 'date',
            placeholder: 'dd/mm/yyyy'
          },
          {
            id: 'status',
            label: t('common.fields.status'),
            type: 'select',
            options: [
              { value: 'pending', label: t('admin.status.pending') },
              { value: 'confirmed', label: t('admin.status.confirmed') },
              { value: 'shipping', label: t('admin.status.shipping') },
              { value: 'delivered', label: t('admin.status.delivered') },
              { value: 'cancelled', label: t('admin.status.cancelled') },
            ]
          },
          {
            id: 'paymentStatus',
            label: t('common.fields.payment'),
            type: 'select',
            options: [
              { value: 'paid', label: t('admin.status.paid') },
              { value: 'pending', label: t('admin.status.unpaid') },
            ]
          },
          {
            id: 'amountFrom',
            label: t('admin.filters.amountFrom'),
            type: 'number',
            placeholder: '0'
          },
          {
            id: 'amountTo',
            label: t('admin.filters.amountTo'),
            type: 'number',
            placeholder: '0'
          },
          {
            id: 'customer',
            label: t('common.fields.customer'),
            type: 'text',
            placeholder: t('common.placeholders.search')
          },
          {
            id: 'code',
            label: t('common.fields.orderCode'),
            type: 'text',
            placeholder: t('common.placeholders.enterCode')
          }
        ]}

        // Visibility
        visibleColumns={visibleColumns}
        onColumnVisibilityChange={setVisibleColumns}

        emptyMessage={t('common.noResults')}

        // Selection
        selectedIds={new Set()}
        onSelectionChange={() => {}}
      />

      <ConfirmDialog
        isOpen={!!orderToDelete}
        onClose={() => setOrderToDelete(null)}
        onConfirm={handleDelete}
        title={t('admin.actions.delete')}
        message={t('messages.confirmDelete')}
        isLoading={deleteMutation.isPending}
        variant="danger"
      />

      {/* Order Detail Modal */}
      <Modal
        isOpen={!!selectedOrder}
        onClose={() => setSelectedOrder(null)}
        title={`${t('admin.actions.view')} ${t('common.fields.orderCode')}: ${selectedOrder?.code}`}
        size="lg"
        footer={
          selectedOrder && (
            <div className="flex justify-end gap-3">
              <Button variant="outline" onClick={() => setSelectedOrder(null)}>{t('common.close')}</Button>
              {selectedOrder.status === 'pending' && (
                <Button onClick={() => updateStatus(selectedOrder.code, 'confirmed')}>{t('admin.actions.confirmOrderFull')}</Button>
              )}
              {selectedOrder.status === 'delivered' && (
                <Button leftIcon={<Printer size={16} />} onClick={handlePrintInvoice}>{t('admin.actions.printInvoice')}</Button>
              )}
            </div>
          )
        }
      >
        {selectedOrder && (
          <div className="space-y-6">
            {/* Status */}
            <div className="flex items-center gap-4">
              <Badge color={getStatusColor(selectedOrder.status) as "success" | "warning" | "error" | "info" | "primary" | "secondary"}>
                {getStatusText(selectedOrder.status)}
              </Badge>
              <Badge color={selectedOrder.paymentStatus === 'paid' ? 'success' : 'warning'}>
                {selectedOrder.paymentStatus === 'paid' ? t('admin.payment.paid') : t('admin.payment.pending')}
              </Badge>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {/* Customer Info */}
              <div className="bg-secondary rounded-lg p-4">
                <h3 className="font-semibold mb-2">{t('admin.order.customerInfo')}</h3>
                <p className="font-medium">{selectedOrder.shippingName || selectedOrder.userCode}</p>
                <p className="text-secondary text-sm">{selectedOrder.shippingPhone || '-'}</p>
                <p className="text-secondary text-sm mt-1">{selectedOrder.shippingAddress || '-'}</p>
              </div>

              {/* Order Info */}
              <div className="bg-secondary rounded-lg p-4">
                <h3 className="font-semibold mb-2">{t('admin.order.orderInfo')}</h3>
                <p className="text-secondary text-sm">{t('admin.order.orderDate')}: {formatDate(selectedOrder.orderDate)}</p>
                <p className="text-secondary text-sm">{t('common.fields.paymentMethod')}: {selectedOrder.paymentMethod === 'cod' ? t('admin.order.paymentMethodCod') : t('admin.order.paymentMethodTransfer')}</p>
              </div>
            </div>

            {/* Items */}
            <div>
              <h3 className="font-semibold mb-3">{t('common.products')}</h3>
              <div className="space-y-3 border rounded-lg p-3 bg-primary">
                {selectedOrder.orderItems?.map((item, index) => (
                  <div key={index} className="flex items-center gap-3 py-2 border-b last:border-0">
                    <img 
                      src={item.productImage || defaultImage} 
                      alt={item.productName} 
                      className="w-12 h-12 object-cover rounded border"
                      onError={(e) => {
                        (e.target as HTMLImageElement).src = defaultImage;
                      }}
                    />
                    <div className="flex-1">
                      <p className="font-medium text-sm">{item.productName}</p>
                      <p className="text-xs text-tertiary">{t('common.fields.quantity')}: {item.quantity}</p>
                    </div>
                    <p className="font-medium">{formatCurrency(item.priceAtOrder * item.quantity)}</p>
                  </div>
                ))}
              </div>
            </div>

            {/* Summary */}
            <div className="border-t pt-4 space-y-2">
              <div className="flex justify-between text-sm">
                <span className="text-secondary">{t('admin.order.subtotal')}</span>
                <span>{formatCurrency(selectedOrder.totalAmount)}</span>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-secondary">{t('admin.order.shippingFee')}</span>
                <span>{formatCurrency(selectedOrder.shippingFee)}</span>
              </div>
              <div className="flex justify-between text-sm">
                <span className="text-secondary">{t('admin.order.discount')}</span>
                <span className="text-success">-{formatCurrency(selectedOrder.discountAmount || 0)}</span>
              </div>
              <div className="flex justify-between font-bold text-lg pt-2 border-t">
                <span>{t('admin.order.grandTotal')}</span>
                <span className="text-error">{formatCurrency(selectedOrder.finalAmount)}</span>
              </div>
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
};

export default OrdersPage;

import { useState, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { Package, AlertTriangle, Star, XCircle } from 'lucide-react';
import { Button, Badge, Modal, ConfirmDialog } from '@/components/ui';

import { formatCurrency, getImageUrl } from '@/utils/format';
import { ProductForm, ProductFormData } from './forms/ProductForm';
import {
  useProducts,
  useEntityManager,
} from '@/hooks';
import { useQuery } from '@tanstack/react-query';
import { productService, type CreateProductRequest, type UpdateProductRequest } from '@/services/productService';
import { useToast } from '@/store';
import type { Product } from '@/types';
import { DataTable, type DataTableColumn } from '@/components/common/DataTable';
import { AdminPageHeader } from '@/components/admin';
import { PaginationDefaults, SortDirection } from '@/constants';
import { PRODUCT_LIST_FIELDS } from '@/constants/fieldConstants';
import { StatsCards, StatItem } from '@/components/admin/StatsCards';

// Types for sorting
type SortField = 'name' | 'price' | 'stock' | 'createdAt';

export const ProductsPage = () => {
  const { t, i18n } = useTranslation();
  const toast = useToast();

  // Helper to safely get image URL regardless of casing
  const getSafeImageUrl = (img: string | { imageURL?: string; imageUrl?: string; ImageURL?: string } | null | undefined) => {
      if (!img) return '';
      if (typeof img === 'string') return getImageUrl(img);
      const imageObj = img as { imageURL?: string; imageUrl?: string; ImageURL?: string };
      return getImageUrl(imageObj.imageURL || imageObj.imageUrl || imageObj.ImageURL || '');
  };

  // Helper to extract detail/spec value
  const getDetailValue = (details: { specName: string; specValue: string }[] | undefined, keys: string[]) => {
      if (!details) return undefined;
      const detail = details.find(d => keys.some(k => d.specName?.toLowerCase() === k.toLowerCase()));
      return detail?.specValue;
  };

  // State
  const [currentPage, setCurrentPage] = useState<number>(PaginationDefaults.PAGE_INDEX);
  const [pageSize, setPageSize] = useState<number>(PaginationDefaults.PAGE_SIZE);
  const [searchQuery, setSearchQuery] = useState<string>('');
  const [advancedFilters, setAdvancedFilters] = useState<Record<string, string>>({});

  // Sorting
  const [sortField, setSortField] = useState<SortField>('createdAt');
  const [sortDir, setSortDir] = useState<SortDirection>(SortDirection.DESC);

  // Import
  const handleImportProduct = async (file: File) => {
    try {
        await productService.import(file);
        toast.success(t('common.messages.importSuccess') || 'Import successful');
        refetch();
    } catch (error) {
        toast.error(t('common.messages.importError') || 'Import failed');
        throw error; // Let modal handle error state if needed
    }
  };

  // Fetch API
  const {
    data: productsData,
    isLoading,
    isFetching,
    isError,
    error,
    refetch,
  } = useProducts({
    pageIndex: currentPage,
    pageSize,
    search: searchQuery || undefined,
    sortField,
    sortDir,
    fields: PRODUCT_LIST_FIELDS.length > 0 ? PRODUCT_LIST_FIELDS : undefined,  // Selective columns for list view
    ...advancedFilters
  });

  // Fetch Stats
  const { data: statsData, isLoading: isStatsLoading } = useQuery({
      queryKey: ['product-stats'],
      queryFn: () => productService.getStats(),
      staleTime: 60000,
  });

  const stats: StatItem[] = [
    {
      label: t('admin.stats.totalProducts'),
      value: statsData?.total || 0,
      icon: <Package size={24} />,
      color: 'blue',
      loading: isStatsLoading
    },
    {
      label: t('admin.stats.lowStock'),
      value: statsData?.lowStock || 0,
      icon: <AlertTriangle size={24} />,
      color: 'amber',
      loading: isStatsLoading
    },
    {
      label: t('admin.stats.outOfStock'),
      value: statsData?.outOfStock || 0,
      icon: <XCircle size={24} />,
      color: 'rose',
      loading: isStatsLoading
    }
  ];

  const products: Product[] = productsData?.products || [];
  const totalItems: number = productsData?.totalItems || 0;
  const totalPages: number = Math.ceil(totalItems / pageSize) || 1;

  // Mutations and State via useEntityManager
  const {
    isFormOpen,
    editingItem: editingProduct,
    itemToDelete: productToDelete,
    isDeleting,
    openCreate,
    openEdit,
    closeForm,
    confirmDelete,
    cancelDelete,
    createMutation,
    updateMutation,
    deleteMutation
  } = useEntityManager<Product, CreateProductRequest, UpdateProductRequest>({
    service: productService,
    queryKey: ['products'],
    includeChildrenOnEdit: true,
  });

  // Selection State
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const selectedToDelete = products.filter(p => selectedIds.has(p.code));
  const [showBulkConfirm, setShowBulkConfirm] = useState(false);

  // View State
  const [viewingProduct, setViewingProduct] = useState<Product | null>(null);
  const handleOpenView = (product: Product) => setViewingProduct(product);

  // Handlers
  const handleSort = (field: string, dir: 'asc' | 'desc') => {
    setSortField(field as SortField);
    setSortDir(dir as SortDirection);
    setCurrentPage(PaginationDefaults.PAGE_INDEX);
  };

  const handleAdvancedSearch = (filters: Record<string, string>) => {
    setAdvancedFilters(filters);
    setCurrentPage(PaginationDefaults.PAGE_INDEX);
    // Sync text search
    setSearchQuery(filters.search || '');
  };

  const handleReset = () => {
    setAdvancedFilters({});
    setCurrentPage(PaginationDefaults.PAGE_INDEX);
    setPageSize(PaginationDefaults.PAGE_SIZE);
    setSearchQuery('');
    setSortField('createdAt');
    setSortDir(SortDirection.DESC);
  };

  const handleCreate = async (data: ProductFormData) => {
    try {
      await createMutation.mutateAsync({
        name: data.name,
        description: data.description,
        price: data.price,
        categoryCode: data.categoryCode,
        stockQuantity: data.stockQuantity,
        costPrice: data.costPrice,

        weight: data.weight,
        supplierCode: data.supplierCode || undefined,
        brandCode: data.brandCode || undefined,
        color: data.color,
        power: data.power,
        voltage: data.voltage,
        material: data.material,
        size: data.size,
        images: data.images,
        isActive: data.isActive,
        details: data.details,
        baseUnit: data.baseUnit,
        minStockLevel: data.minStockLevel,
        binLocation: data.binLocation,
        vatRate: data.vatRate,
        countryOfOrigin: data.countryOfOrigin,
        productUnits: (data.productUnits as any) || [],
      });
    } catch {
      // Error handled by hook
    }
  };

  const handleUpdate = async (data: ProductFormData) => {
    if (!editingProduct) return;
    try {
      await updateMutation.mutateAsync({
        id: editingProduct.code, 
        data: {
          name: data.name,
          description: data.description,
          price: data.price,
          categoryCode: data.categoryCode,
          stockQuantity: data.stockQuantity,
          costPrice: data.costPrice,

          weight: data.weight,
          supplierCode: data.supplierCode || undefined,
          brandCode: data.brandCode || undefined,
          color: data.color,
          power: data.power,
          voltage: data.voltage,
          material: data.material,
          size: data.size,
          images: data.images,
          isActive: data.isActive,
          details: data.details,
          baseUnit: data.baseUnit,
          minStockLevel: data.minStockLevel,
          binLocation: data.binLocation,
          vatRate: data.vatRate,
          countryOfOrigin: data.countryOfOrigin,
          productUnits: (data.productUnits as any) || [],
        },
      });
    } catch {
      // Error handled by hook
    }
  };

  const handleDelete = async () => {
    if (productToDelete) {
      deleteMutation.mutate(productToDelete.code);
    } else if (selectedToDelete.length > 0) {
      try {
        await Promise.all(selectedToDelete.map(item => deleteMutation.mutateAsync(item.code)));
        setSelectedIds(new Set()); // Clear selection
        setShowBulkConfirm(false);
        toast.success(t('common.deleteSuccess'));
      } catch {
        // Errors handled by mutation individually
      }
    }
  };

  // Override cancelDelete to clear local state too
  const handleCancelDelete = () => {
    cancelDelete(); // from hook
    setShowBulkConfirm(false);
    // Don't clear selection on cancel - user may want to keep their selection
  };

  // Column Definitions
  const columns: DataTableColumn<Product>[] = [
    {
      id: 'image',
      header: t('common.fields.image'),
      width: '120px',
      className: 'text-center',
      accessor: (product) => (
        <div className="flex flex-col items-center">
            <div className="w-10 h-10 rounded-lg overflow-hidden bg-gray-100 dark:bg-slate-700 border border-gray-200 dark:border-slate-600">
               {(product.images?.[0] || product.productImages?.[0]) ? (
                 <img 
                   src={getSafeImageUrl(product.images?.[0] || product.productImages?.[0])} 
                   alt={product.name} 
                   className="w-full h-full object-cover"
                   onError={(e) => console.error("Img Error:", e.currentTarget.src)}
                 />
               ) : (
                 <div className="w-full h-full flex items-center justify-center text-gray-400">
                   <Package size={18} />
                 </div>
               )}
            </div>
        </div>
      )
    },
    {
      id: 'name',
      header: t('common.fields.name'),
      accessor: (product) => (
        <div>
          <p className="font-medium text-sm text-slate-700 dark:text-slate-200">{product.name}</p>
          <p className="text-xs text-slate-500">{product.brand}</p>
        </div>
      ),
      sortable: true
    },
    {
      id: 'category',
      header: t('common.fields.category'),
      accessor: 'category',
    },
    {
      id: 'price',
      header: t('common.fields.price'),
      accessor: (product) => (
        product.price > 0 ? (
          <span className="font-semibold text-rose-600">{formatCurrency(product.price)}</span>
        ) : (
          <Badge color="primary" size="sm">{t('common.fields.contact')}</Badge>
        )
      ),
      className: 'text-right',
      headerClassName: 'text-right',
      sortable: true
    },
    {
      id: 'stock',
      header: t('common.fields.stock'),
      accessor: (product) => (
        <span className={product.stock > 10 ? 'text-emerald-600 font-medium' : product.stock > 0 ? 'text-amber-600 font-medium' : 'text-rose-600 font-medium'}>
          {product.stock}
        </span>
      ),
      className: 'text-center',
      headerClassName: 'text-center',
      sortable: true
    },
    {
      id: 'rating',
      header: t('common.fields.rating'),
      accessor: (product) => (
        <div className="flex items-center justify-center gap-1 text-sm">
          <Star size={16} className="text-amber-400 fill-amber-400" />
          <span>{product.rating} ({product.reviewCount})</span>
        </div>
      ),
      className: 'text-center',
      headerClassName: 'text-center'
    },
    {
      id: 'status',
      header: t('common.fields.status'),
      accessor: (product) => (
        <Badge
          color={product.isActive !== false ? 'success' : 'error'}
          size="sm"
          variant="outline"
        >
          {product.isActive !== false ? t('common.status.active') : t('common.status.inactive')}
        </Badge>
      ),
      className: 'text-center',
      headerClassName: 'text-center'
    },
    {
      id: 'createdAt',
      header: t('common.fields.createdAt') || 'Created At',
      accessor: (product) => (
        <span className="text-sm text-slate-500">
           {new Date(product.createdAt).toLocaleDateString(i18n.language, { year: 'numeric', month: 'short', day: 'numeric' })}
        </span>
      ),
      className: 'text-center',
      headerClassName: 'text-center',
      sortable: true
    }
  ];

      const productInitialData = useMemo(() => editingProduct ? {
        name: editingProduct.name,
        description: editingProduct.description,
        price: editingProduct.price,
        categoryCode: editingProduct.categoryCode,
        stockQuantity: editingProduct.stockQuantity ?? editingProduct.stock,
        images: editingProduct.images || [],
        productImages: editingProduct.productImages,
        details: editingProduct.details,
        color: editingProduct.color || getDetailValue(editingProduct.details, ['color', 'màu', 'màu sắc']),
        power: editingProduct.power || getDetailValue(editingProduct.details, ['power', 'công suất']),
        voltage: editingProduct.voltage || getDetailValue(editingProduct.details, ['voltage', 'điện áp']),
        material: editingProduct.material || getDetailValue(editingProduct.details, ['material', 'chất liệu']),
        size: editingProduct.size || getDetailValue(editingProduct.details, ['size', 'kích thước']),
        weight: editingProduct.weight || (getDetailValue(editingProduct.details, ['weight', 'khối lượng']) ? Number(getDetailValue(editingProduct.details, ['weight', 'khối lượng'])) : undefined),
        supplierCode: editingProduct.supplierCode,
        brandCode: editingProduct.brandCode,
        isActive: editingProduct.isActive,
        categoryName: editingProduct.category,
        brandName: editingProduct.brand,
        supplierName: editingProduct.supplierName,
        baseUnit: editingProduct.baseUnit,
        vatRate: editingProduct.vatRate,
        minStockLevel: editingProduct.minStockLevel,
        binLocation: editingProduct.binLocation,
        countryOfOrigin: editingProduct.countryOfOrigin || getDetailValue(editingProduct.details, ['origin', 'xuất xứ', 'nước sản xuất']),
        productUnits: editingProduct.productUnits,
      } : undefined, [editingProduct]);

      return (
