                    <motion.div
                        initial={{ opacity: 0, x: 20 }}
                        animate={{ opacity: 1, x: 0 }}
                        className="bg-gradient-to-br from-indigo-100 to-purple-100 rounded-2xl h-80 flex items-center justify-center"
                    >
                        <Users size={120} className="text-indigo-600/30" />
                    </motion.div>
                </div>

                {/* Values */}
                <h2 className="text-3xl font-bold text-center mb-10">{t('about.valuesTitle')}</h2>
                <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-6">
                    {values.map((value, index) => (
                        <motion.div
                            key={index}
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            transition={{ delay: index * 0.1 }}
                            className="bg-primary rounded-xl p-6 shadow-md"
                        >
                            <div className="w-12 h-12 bg-indigo-100 rounded-lg flex items-center justify-center mb-4">
                                <value.icon className="text-indigo-600" size={24} />
                            </div>
                            <h3 className="font-bold mb-2">{value.title}</h3>
                            <p className="text-sm text-secondary">{value.desc}</p>
                        </motion.div>
                    ))}
                </div>
            </div>
        </div>
    );
};

export default AboutPage;

import { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { ChevronRight, CreditCard, Truck, MapPin, Phone, User, Mail, FileText } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Button, Input, Select, Modal } from '@/components/ui';
import CustomImage from '@/components/common/Image';
import { useCartStore, useAuthStore, useToast } from '@/store'; // Consolidated import
import { formatCurrency } from '@/utils/format';
import { orderService, type CreateOrderRequest } from '@/services/orderService';
import { paymentService } from '@/services/paymentService';
import { PaymentMethod } from '@/constants';
import { useCheckoutStore } from '@/store/checkoutStore';

export const CheckoutPage = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const toast = useToast();
  const { items, getTotal, clearCart, fetchCart } = useCartStore();
  const { user, isAuthenticated } = useAuthStore();
  
  // Store hooks
  const { 
    step, setStep, 
    formData, setFormData, 
    paymentMethod, setPaymentMethod, 
    voucherCode, setVoucherCode,
    resetCheckout 
  } = useCheckoutStore();

  const [showLoginModal, setShowLoginModal] = useState(false);
  const [isGuestCheckout, setIsGuestCheckout] = useState(true); // Default to true to unblock testing

  useEffect(() => {
    if (!isAuthenticated && !isGuestCheckout) {
      setShowLoginModal(true);
    } else {
      setShowLoginModal(false);
    }
  }, [isAuthenticated, isGuestCheckout]);
  
  // Sync user info to form if empty
  useEffect(() => {
     if (isAuthenticated && user && !formData.fullName) {
         setFormData({
             fullName: user.fullName || '',
             phone: user.phone || '',
             email: user.email || ''
         });
     }
  }, [isAuthenticated, user]);

  const [isProcessing, setIsProcessing] = useState(false);

  const subtotal = getTotal();
  const shippingFee = subtotal >= 500000 ? 0 : 30000;
  const total = subtotal + shippingFee;

  // Pre-fill if user has address (Logic omitted for brevity, could use userService.getMyAddresses())

  const handleInputChange = (field: string, value: string) => {
    setFormData({ [field]: value });
  };

  // Voucher Logic
  const [appliedVoucher, setAppliedVoucher] = useState<{ code: string, discount: number, type: string } | null>(null);

  const handleApplyVoucher = async () => {
    if (!voucherCode.trim()) return;
    try {
      const res = await import('@/services/promotionService').then(m => m.promotionService.getByCode(voucherCode));
      if (res.success && res.data) {
        const promo = res.data;
        // Validate
        const now = new Date();
        const startDate = new Date(promo.startDate);
        const endDate = new Date(promo.endDate);

        if (!promo.isActive || startDate > now || endDate < now) {
          toast.error(t('checkout.voucherExpired') || 'Mã giảm giá không hợp lệ hoặc đã hết hạn');
          return;
        }

        if (promo.minOrderAmount !== undefined && subtotal < promo.minOrderAmount) {
          toast.error(`${t('checkout.minOrderAmount') || 'Đơn hàng tối thiểu'}: ${formatCurrency(promo.minOrderAmount)}`);
          return;
        }

        // Calculate Discount
        let discountCount = 0;
        if (promo.discountType === 'PERCENTAGE') {
          discountCount = subtotal * (promo.discountValue / 100);
          if (promo.maxDiscountAmount) discountCount = Math.min(discountCount, promo.maxDiscountAmount);
        } else {
          discountCount = promo.discountValue;
        }

        setAppliedVoucher({
          code: promo.code,
          discount: discountCount,
          type: promo.discountType
        });
        toast.success(t('checkout.voucherApplied') || 'Áp dụng mã giảm giá thành công');
      } else {
        toast.error(res.message || t('checkout.voucherInvalid') || 'Mã giảm giá không tồn tại');
      }
    } catch (e) {
      toast.error(t('checkout.voucherError') || 'Lỗi kiểm tra mã giảm giá');
    }
  };

  const discountAmount = appliedVoucher ? appliedVoucher.discount : 0;
  // Recalculate total with discount
  const finalTotal = Math.max(0, subtotal + shippingFee - discountAmount);

  /* Validation Regex */
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const phoneRegex = /^(0[3|5|7|8|9])+([0-9]{8})$/;

  const [errors, setErrors] = useState({
      email: '',
      phone: ''
  });

  const validate = () => {
    let isValid = true;
    const newErrors = { email: '', phone: '' };

    if (formData.email && !emailRegex.test(formData.email)) {
        newErrors.email = t('validation.invalidEmail') || 'Email không hợp lệ';
        isValid = false;
    }

    if (!phoneRegex.test(formData.phone)) {
        newErrors.phone = t('validation.invalidPhone') || 'Số điện thoại không hợp lệ (VD: 0901234567)';
        isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  const handleSubmit = async () => {
    setIsProcessing(true);
    try {
      // Validation
      if (!formData.fullName || !formData.phone || !formData.address || !formData.city || !formData.district) {
        toast.error(t('validation.required') || 'Vui lòng điền đầy đủ thông tin giao hàng');
        setIsProcessing(false);
        return;
      }

      if (!validate()) {
          toast.error(t('validation.checkErrors') || 'Vui lòng kiểm tra lại thông tin giao hàng');
          setStep(1); // Go back to step 1 to show errors
          setIsProcessing(false);
          return;
      }

      const orderData: CreateOrderRequest = {
        fullName: formData.fullName,
        email: formData.email,
        phone: formData.phone,
        address: formData.address,
        city: formData.city,
        district: formData.district,
        ward: formData.ward,
        note: formData.note,
        paymentMethod: paymentMethod,
        couponCode: appliedVoucher?.code,
        items: items.map(item => ({
          productCode: item.product.code,
          quantity: item.quantity,
          size: item.size,
          color: item.color
        }))
      };

      // 1. Create Order
      const orderRes = await orderService.create(orderData);

      if (orderRes.success && orderRes.data) {
        const orderCode = orderRes.data.code;
        toast.success(t('messages.orderSuccess') || 'Đặt hàng thành công!');
        
        resetCheckout(); // RESET STORE

        // 2. Process Payment
        try {
          // Use the ACTUAL final amount from backend response if available, else local calc
          const totalAmount = orderRes.data.finalAmount || finalTotal;
          await paymentService.create({
            orderCode: orderCode,
            paymentMethod: paymentMethod,
            amount: totalAmount
          });
        } catch (paymentError) {
          console.error('Payment creation failed', paymentError);
          toast.error(t('messages.paymentError') || 'Có lỗi khi tạo thanh toán, vui lòng liên hệ CSKH.');
        }

        // 3. Clear Cart & Redirect
        if (isAuthenticated) {
          await fetchCart();
        } else {
          await clearCart();
        }
        navigate(`/order-success?code=${orderCode}`);
      } else {
        toast.error(orderRes.message || t('messages.orderError') || 'Đặt hàng thất bại');
      }
    } catch (error: unknown) {
      console.error('Order failed', error);
      const msg = error instanceof Error ? error.message : t('messages.generalError') || 'Có lỗi xảy ra';
      toast.error(msg);
    } finally {
      setIsProcessing(false);
    }
  };

  // Re-fetch cart if empty? No, handled by App/ShopLayout.

  if (items.length === 0) {
    return (
      <div className="min-h-screen bg-secondary flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-2xl font-bold mb-4">{t('cart.empty')}</h1>
          <Link to="/products">
            <Button>{t('cart.continueShopping')}</Button>
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-secondary">
      {/* Breadcrumb */}
      <div className="bg-primary border-b py-3">
        <div className="container mx-auto px-4 flex items-center gap-2 text-sm">
          <Link to="/" className="text-secondary hover:text-primary">{t('common.home')}</Link>
          <ChevronRight size={14} />
          <Link to="/cart" className="text-secondary hover:text-primary">{t('cart.title')}</Link>
          <ChevronRight size={14} />
          <span className="text-primary font-medium">{t('checkout.title')}</span>
        </div>
      </div>

      <div className="container mx-auto px-4 py-8">
        {/* Progress Steps */}
        <div className="flex items-center justify-center mb-8">
          {[
            { num: 1, label: t('checkout.shipping') },
            { num: 2, label: t('checkout.payment') },
            { num: 3, label: t('checkout.confirm') },
          ].map((s, i) => (
            <div key={s.num} className="flex items-center">
              <div
                className={`w-10 h-10 rounded-full flex items-center justify-center font-bold ${step >= s.num ? 'bg-primary text-white' : 'bg-tertiary text-secondary'
                  }`}
              >
                {s.num}
              </div>
              <span className={`ml-2 hidden sm:inline ${step >= s.num ? 'text-primary' : 'text-tertiary'}`}>
                {s.label}
              </span>
              {i < 2 && <div className={`w-12 h-1 mx-4 ${step > s.num ? 'bg-primary' : 'bg-tertiary'}`} />}
            </div>
          ))}
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Form */}
          <div className="lg:col-span-2">
            {/* Step 1: Shipping */}
            {step === 1 && (
              <div className="bg-primary rounded-xl p-6">
                <h2 className="text-xl font-bold mb-6 flex items-center gap-2">
                  <Truck size={24} />
                  {t('checkout.shippingInfo')}
                </h2>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <Input
                    label={t('checkout.fullName')}
                    placeholder="Nguyễn Văn A"
                    value={formData.fullName}
                    onChange={(e) => handleInputChange('fullName', e.target.value)}
                    leftIcon={<User size={18} />}
                    required
                    isRequired
                  />
                  <Input
                    label={t('checkout.phone')}
                    placeholder="0901234567"
                    value={formData.phone}
                    onChange={(e) => {
                        handleInputChange('phone', e.target.value);
                        if(errors.phone) setErrors({...errors, phone: ''});
                    }}
                    leftIcon={<Phone size={18} />}
                    required
                    isRequired
                    error={errors.phone}
                  />
                  <div className="md:col-span-2">
                    <Input
                      label={t('shared.email')}
                      type="email"
                      placeholder="email@example.com"
                      value={formData.email}
                      onChange={(e) => {
                          handleInputChange('email', e.target.value);
                          if(errors.email) setErrors({...errors, email: ''});
                      }}
                      leftIcon={<Mail size={18} />}
                      error={errors.email}
                    />
                  </div>
                    <Select
                      label={t('checkout.city')}
                      value={formData.city}
                      onChange={(e) => handleInputChange('city', e.target.value)}
                      options={[
                        { value: '', label: 'Chọn Tỉnh/Thành phố' },
                        { value: 'hcm', label: 'TP. Hồ Chí Minh' },
                        { value: 'hn', label: 'Hà Nội' },
                        { value: 'dn', label: 'Đà Nẵng' },
                      ]}
                      required
                      isRequired
                    />
                    <Select
                      label={t('checkout.district')}
                      value={formData.district}
                      onChange={(e) => handleInputChange('district', e.target.value)}
                      options={[
                        { value: '', label: 'Chọn Quận/Huyện' },
                        { value: 'q1', label: 'Quận 1' },
                        { value: 'q3', label: 'Quận 3' },
                        { value: 'q7', label: 'Quận 7' },
                      ]}
                      required
                      isRequired
                    />
                  <div className="md:col-span-2">
                    <Input
                      label={t('checkout.address')}
                      placeholder="Số nhà, tên đường..."
                      value={formData.address}
                      onChange={(e) => handleInputChange('address', e.target.value)}
                      leftIcon={<MapPin size={18} />}
                      required
                      isRequired
                    />
                  </div>
                  <div className="md:col-span-2">
                    <Input
                      label={t('checkout.note')}
                      placeholder="Ghi chú đơn hàng (không bắt buộc)"
                      value={formData.note}
                      onChange={(e) => handleInputChange('note', e.target.value)}
                      leftIcon={<FileText size={18} />}
                    />
                  </div>
                </div>

                <div className="mt-6 flex justify-end">
                  <Button size="lg" onClick={() => {
                    if (!formData.fullName || !formData.phone || !formData.address || !formData.city || !formData.district) {
                      toast.error(t('validation.required') || 'Vui lòng điền đầy đủ thông tin giao hàng');
                      return;
                    }
                    if (!validate()) {
                      toast.error(t('validation.checkErrors') || 'Vui lòng kiểm tra lại thông tin');
                      return;
                    }
                    setStep(2);
                  }}>
                    {t('checkout.continue')}
                  </Button>
                </div>
              </div>
            )}

            {/* Step 2: Payment */}
            {step === 2 && (
              <div className="bg-primary rounded-xl p-6">
                <h2 className="text-xl font-bold mb-6 flex items-center gap-2">
                  <CreditCard size={24} />
                  {t('checkout.paymentMethod')}
                </h2>

                <div className="space-y-4">
                    {[
                      { value: PaymentMethod.COD, label: 'Thanh toán khi nhận hàng (COD)', icon: '💵' },
                      { value: 'ZALOPAY', label: 'ZaloPay', icon: '💳' },
                      { value: 'MOMO', label: 'Ví MoMo', icon: '📱' },
                      { value: 'VNPAY', label: 'VNPAY QR', icon: '🏦' },
                      { value: PaymentMethod.BANK_TRANSFER, label: 'Chuyển khoản ngân hàng', icon: '🏛️' },
                    ].map((method) => (
                      <label
                        key={method.value}
                        className={`flex items-center gap-4 p-4 border-2 rounded-xl cursor-pointer transition-colors ${paymentMethod === method.value ? 'border-primary bg-primary/5' : 'hover:border-primary/50'
                          }`}
                      >
                        <input
                          type="radio"
                          name="payment"
                          value={method.value}
                          checked={paymentMethod === method.value}
                          onChange={(e) => setPaymentMethod(e.target.value)}
                          className="w-5 h-5 text-primary"
                        />
                        <div className="flex-1">
                          <div className="flex items-center gap-3">
                            <span className="text-2xl">{method.icon}</span>
                            <span className="font-medium">{method.label}</span>
                          </div>
                          {paymentMethod === PaymentMethod.BANK_TRANSFER && method.value === PaymentMethod.BANK_TRANSFER && (
                            <motion.div
                              initial={{ height: 0, opacity: 0 }}
                              animate={{ height: 'auto', opacity: 1 }}
                              className="mt-3 p-4 bg-tertiary rounded-lg text-xs space-y-1"
                            >
                              <p className="font-bold text-primary">{t('checkout.bankInfo')}</p>
                              <p>{t('common.fields.bankName')}: <strong>{t('checkout.bankName')}</strong></p>
                              <p>{t('common.fields.bankAccount')}: <strong>{t('checkout.accountNumber')}</strong></p>
                              <p>{t('common.fields.accountHolder') || 'Chủ tài khoản'}: <strong>{t('checkout.accountHolder')}</strong></p>
                              <p>{t('common.fields.note')}: <strong>{t('checkout.transferContent')}</strong></p>
                          </motion.div>
                        )}
                      </div>
                    </label>
                  ))}
                </div>

                <div className="mt-6 flex justify-between">
                  <Button variant="outline" onClick={() => setStep(1)}>
                    {t('common.back')}
                  </Button>
                  <Button size="lg" onClick={() => setStep(3)}>
                    {t('checkout.continue')}
                  </Button>
                </div>
              </div>
            )}

            {/* Step 3: Confirm */}
            {step === 3 && (
              <div className="bg-primary rounded-xl p-6">
                <h2 className="text-xl font-bold mb-6">{t('checkout.confirmOrder')}</h2>

                {/* Shipping Summary */}
                <div className="mb-6 p-4 bg-secondary rounded-lg">
                  <h3 className="font-semibold mb-2">{t('checkout.shippingInfo')}</h3>
                  <p>{formData.fullName}</p>
                  <p>{formData.phone}</p>
                  <p>{formData.address}, {formData.district}, {formData.city}</p>
                </div>

                {/* Payment Summary */}
                <div className="mb-6 p-4 bg-secondary rounded-lg">
                  <h3 className="font-semibold mb-2">{t('checkout.paymentMethod')}</h3>
                  <p className="capitalize">{paymentMethod}</p>
                </div>

                {/* Order Items */}
                <div className="space-y-3 mb-6">
                  {items.map((item) => (
                    <div key={item.code} className="flex items-center gap-4">
                      <div className="w-16 h-16 rounded-lg overflow-hidden bg-secondary flex-shrink-0">
                        <CustomImage
                          src={item.product.image}
                          alt={item.product.name}
                          className="w-full h-full object-cover"
                        />
                      </div>
                      <div className="flex-1">
                        <p className="font-medium line-clamp-1">{item.product.name}</p>
                        <p className="text-sm text-tertiary">x{item.quantity}</p>
                      </div>
                      <p className="font-bold">{formatCurrency(item.product.price * item.quantity)}</p>
                    </div>
                  ))}
                </div>

                <div className="mt-6 flex justify-between">
                  <Button variant="outline" onClick={() => setStep(2)}>
                    {t('common.back')}
                  </Button>
                  <Button size="lg" onClick={handleSubmit} isLoading={isProcessing}>
                    {t('checkout.placeOrder')}
                  </Button>
                </div>
              </div>
            )}
          </div>

          {/* Order Summary */}
          <div className="lg:col-span-1">
            <div className="bg-primary rounded-xl p-6 sticky top-24">
              <h2 className="text-lg font-bold mb-4">{t('cart.orderSummary')}</h2>

              <div className="space-y-3 mb-4 max-h-64 overflow-y-auto">
                {items.map((item) => (
                  <div key={item.code} className="flex gap-3 text-sm">
                    <div className="w-12 h-12 rounded overflow-hidden bg-secondary flex-shrink-0">
                      <CustomImage
                        src={item.product.image}
                        alt={item.product.name}
                        className="w-full h-full object-cover"
                      />
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="font-medium truncate">{item.product.name}</p>
                      <p className="text-tertiary">x{item.quantity}</p>
                    </div>
                    <p className="font-medium">{formatCurrency(item.product.price * item.quantity)}</p>
                  </div>
                ))}
              </div>

              <hr className="my-4" />

              <div className="space-y-2">
                {/* Voucher Input */}
                <div className="flex gap-2">
                  <Input
                    placeholder={t('checkout.voucherPlaceholder') || 'Mã giảm giá'}
                    value={voucherCode}
                    onChange={(e) => setVoucherCode(e.target.value.toUpperCase())}
                    className="flex-1"
                  />
                  <Button size="sm" onClick={handleApplyVoucher} disabled={!voucherCode || !!appliedVoucher}>
                    {t('common.apply')}
                  </Button>
                </div>
                {appliedVoucher && (
                  <div className="flex justify-between text-success text-sm items-center bg-success/10 p-2 rounded">
                    <span>Voucher: <strong>{appliedVoucher.code}</strong></span>
                    <button onClick={() => { setAppliedVoucher(null); setVoucherCode(''); }} className="text-secondary hover:text-error">✕</button>
                  </div>
                )}

                <div className="flex justify-between mt-4">
                  <span className="text-secondary">{t('cart.subtotal')}</span>
                  <span>{formatCurrency(subtotal)}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-secondary">{t('cart.shipping')}</span>
                  <span className={shippingFee === 0 ? 'text-success' : ''}>
                    {shippingFee === 0 ? t('cart.free') : formatCurrency(shippingFee)}
                  </span>
                </div>

                {/* Discount Row */}
                {discountAmount > 0 && (
                  <div className="flex justify-between text-success">
                    <span>{t('cart.discount')}</span>
                    <span>-{formatCurrency(discountAmount)}</span>
                  </div>
                )}

                <hr />
                <div className="flex justify-between text-lg font-bold">
                  <span>{t('cart.total')}</span>
                  <span className="text-error">{formatCurrency(finalTotal)}</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Login Required Modal */}
      <Modal
        isOpen={showLoginModal}
        onClose={() => { }} // Block closing by clicking outside? Modal 'closeOnOverlayClick' defaults true.
        // If mandatory, we should disable closing.
        // CheckoutPage usually implies Intent to Checkout. If they cancel, they go back to Cart?
        title={t('checkout.loginRequired') || 'Đăng nhập để thanh toán'}
        showCloseButton={false}
        closeOnOverlayClick={false}
        closeOnEsc={false}
        footer={
          <div className="flex gap-4 w-full justify-end">
            <Button variant="ghost" onClick={() => setIsGuestCheckout(true)}>
              {t('checkout.guestCheckout') || 'Mua hàng không cần đăng nhập'}
            </Button>
            <Link to="/register" state={{ from: '/checkout' }}>
              <Button variant="outline">{t('auth.register')}</Button>
            </Link>
            <Link to="/auth/login" state={{ from: '/checkout' }}>
              <Button>{t('auth.login')}</Button>
            </Link>
          </div>
        }
      >
        <div className="text-secondary">
          <p className="mb-4">
            {t('checkout.loginMessage') || 'Vui lòng đăng nhập hoặc đăng ký tài khoản để tiếp tục thanh toán.'}
          </p>
          <ul className="list-disc list-inside space-y-1 text-sm text-tertiary">
            <li>Tra cứu đơn hàng dễ dàng</li>
            <li>Tích điểm thành viên</li>
            <li>Lưu địa chỉ giao hàng</li>
          </ul>
        </div>
      </Modal>
    </div>
  );
};

export default CheckoutPage;

import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { Scale, X, ShoppingCart, Check, Minus } from 'lucide-react';
import { Button } from '@/components/ui';
import { useCompareStore, useCartStore } from '@/store';
import SharedImage from '@/components/common/Image';
import { formatCurrency } from '@/utils/format';

export const ComparePage = () => {
  const { t } = useTranslation();
  const { items, removeItem, clearCompare } = useCompareStore();
  const addToCart = useCartStore((state) => state.addItem);

  if (items.length === 0) {
    return (
      <div className="min-h-screen bg-secondary">
        <div className="container mx-auto px-4 py-16 text-center">
          <div className="w-24 h-24 mx-auto bg-tertiary rounded-full flex items-center justify-center mb-6">
            <Scale size={48} className="text-tertiary" />
          </div>
          <h1 className="text-2xl font-bold mb-4">{t('compare.empty')}</h1>
          <p className="text-secondary mb-8">{t('compare.emptyMessage')}</p>
          <Link to="/products">
            <Button size="lg">{t('common.browseProducts')}</Button>
          </Link>
        </div>
      </div>
    );
  }

  const specs = ['Thương hiệu', 'Danh mục', 'Đánh giá', 'Tình trạng'];

  return (
    <div className="min-h-screen bg-secondary">
      <div className="container mx-auto px-4 py-8">
        <div className="flex justify-between items-center mb-8">
          <h1 className="text-2xl md:text-3xl font-bold">{t('compare.title')}</h1>
          <Button variant="ghost" onClick={clearCompare}>
            {t('compare.clearAll')}
          </Button>
        </div>

        <div className="bg-primary rounded-xl overflow-x-auto">
          <table className="w-full min-w-[600px]">
            <thead>
              <tr>
                <th className="p-4 text-left w-40"></th>
                {items.map((product) => (
                  <th key={product.code} className="p-4 text-center border-l">
                    <div className="relative">
                      <button
                        onClick={() => removeItem(product.code)}
                        className="absolute -top-2 -right-2 p-1 bg-error text-white rounded-full hover:bg-error/80 transition-colors"
                      >
                        <X size={14} />
                      </button>
                      <Link to={`/product/${product.code}`}>
                        <SharedImage
                          src={product.image}
                          alt={product.name}
                          className="w-32 h-32 object-cover rounded-lg mx-auto mb-3"
                        />
                        <h3 className="font-semibold text-primary hover:text-primary-dark transition-colors line-clamp-2">
                          {product.name}
                        </h3>
                      </Link>
                    </div>
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {/* Price */}
              <tr className="bg-secondary/50">
                <td className="p-4 font-semibold">{t('compare.price')}</td>
                {items.map((product) => (
                  <td key={product.code} className="p-4 text-center border-l">
                    {product.price > 0 ? (
                      <span className="text-xl font-bold text-error">{formatCurrency(product.price)}</span>
                    ) : (
                      <span className="text-primary font-medium">{t('product.contactForPrice')}</span>
                    )}
                  </td>
                ))}
              </tr>

              {/* Brand */}
              <tr>
                <td className="p-4 font-semibold">Thương hiệu</td>
                {items.map((product) => (
                  <td key={product.code} className="p-4 text-center border-l">
                    {product.brand || <Minus size={16} className="mx-auto text-tertiary" />}
                  </td>
                ))}
              </tr>

              {/* Category */}
              <tr className="bg-secondary/50">
                <td className="p-4 font-semibold">Danh mục</td>
                {items.map((product) => (
                  <td key={product.code} className="p-4 text-center border-l">
                    {product.category}
                  </td>
                ))}
              </tr>

              {/* Rating */}
              <tr>
                <td className="p-4 font-semibold">Đánh giá</td>
                {items.map((product) => (
                  <td key={product.code} className="p-4 text-center border-l">
                    <span className="inline-flex items-center gap-1">
                      ⭐ {product.rating} ({product.reviewCount})
                    </span>
                  </td>
                ))}
              </tr>

              {/* Stock */}
              <tr className="bg-secondary/50">
                <td className="p-4 font-semibold">Tình trạng</td>
                {items.map((product) => (
                  <td key={product.code} className="p-4 text-center border-l">
                    {product.stock > 0 ? (
                      <span className="inline-flex items-center gap-1 text-success">
                        <Check size={16} /> Còn hàng
                      </span>
                    ) : (
                      <span className="text-error">Hết hàng</span>
                    )}
                  </td>
                ))}
              </tr>

              {/* Actions */}
              <tr>
                <td className="p-4"></td>
                {items.map((product) => (
                  <td key={product.code} className="p-4 text-center border-l">
                    {product.price > 0 ? (
                      <Button
                        size="sm"
                        onClick={() => addToCart(product)}
                        disabled={product.stock === 0}
                        leftIcon={<ShoppingCart size={16} />}
                      >
                        {t('product.addToCart')}
                      </Button>
                    ) : (
                      <Link to={`/quote-request/${product.code}`}>
                        <Button size="sm" variant="outline">
                          {t('product.requestQuote')}
                        </Button>
                      </Link>
                    )}
                  </td>
                ))}
              </tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default ComparePage;

import { useTranslation } from 'react-i18next';
import { motion } from 'framer-motion';
import { MapPin, Phone, Mail, Clock, Send } from 'lucide-react';
import { Button, Input } from '@/components/ui';
import { useToast } from '@/store';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { createSchemas } from '@/utils/schemas';

export const ContactPage = () => {
    const { t } = useTranslation();
    const { contactSchema } = createSchemas(t);
    type ContactFormData = z.infer<typeof contactSchema>;
    const toast = useToast();
    
    const { register, handleSubmit, reset, formState: { errors } } = useForm<ContactFormData>({
        resolver: zodResolver(contactSchema),
        defaultValues: {
            fullName: '',
            email: '',
            phone: '',
            subject: '',
            message: '',
        }
    });

    const onSubmit = (data: ContactFormData) => {
        toast.success(t('contactPage.success'));
        reset();
    };

    const contactInfo = [
        { icon: MapPin, title: t('contactPage.info.address'), content: '123 Nguyễn Huệ, Quận 1, TP. Hồ Chí Minh' },
        { icon: Phone, title: t('contactPage.info.hotline'), content: '1900 123 456' },
        { icon: Mail, title: t('contactPage.info.email'), content: 'contact@vnvtstore.com' },
        { icon: Clock, title: t('contactPage.info.workingHours'), content: '8:00 - 21:00 (Thứ 2 - CN)' },
    ];

    return (
        <div className="min-h-screen bg-secondary py-12">
            <div className="container mx-auto px-4">
                {/* Header */}
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="text-center mb-12"
                >
                    <h1 className="text-4xl font-bold mb-4">{t('contactPage.title')}</h1>
                    <p className="text-secondary text-lg max-w-2xl mx-auto">
                        {t('contactPage.subtitle')}
                    </p>
                </motion.div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
                    {/* Contact Form */}
                    <motion.div
                        initial={{ opacity: 0, x: -20 }}
                        animate={{ opacity: 1, x: 0 }}
                        className="bg-primary rounded-2xl p-8 shadow-lg"
                    >
                        <h2 className="text-2xl font-bold mb-6">{t('contactPage.formTitle')}</h2>
                        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <Input
                                    label={t('contactPage.fields.fullName')}
                                    placeholder={t('contactPage.placeholders.fullName')}
                                    {...register('fullName')}
                                    error={errors.fullName?.message}
                                    isRequired
                                />
                                <Input
                                    label={t('contactPage.fields.email')}
                                    type="email"
                                    placeholder={t('contactPage.placeholders.email')}
                                    {...register('email')}
                                    error={errors.email?.message}
                                    isRequired
                                />
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <Input
                                    label={t('contactPage.fields.phone')}
                                    placeholder={t('contactPage.placeholders.phone')}
                                    {...register('phone')}
                                    error={errors.phone?.message}
                                />
                                <Input
                                    label={t('contactPage.fields.subject')}
                                    placeholder={t('contactPage.placeholders.subject')}
                                    {...register('subject')}
                                    error={errors.subject?.message}
                                    isRequired
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium mb-2">
                                    {t('contactPage.fields.message')} <span className="text-red-500">*</span>
                                </label>
                                <textarea
                                    rows={5}
                                    placeholder={t('contactPage.placeholders.message')}
                                    {...register('message')}
                                    className={`w-full px-4 py-3 border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/20 transition-all resize-none ${errors.message ? 'border-red-500 bg-red-50/50' : 'border-slate-200'}`}
                                />
                                {errors.message && <p className="text-red-500 text-xs mt-1 font-medium">{errors.message.message}</p>}
                            </div>
                            <Button type="submit" fullWidth rightIcon={<Send size={18} />}>
                                {t('contactPage.send')}
                            </Button>
                        </form>
                    </motion.div>

                    {/* Contact Info */}
                    <motion.div
                        initial={{ opacity: 0, x: 20 }}
                        animate={{ opacity: 1, x: 0 }}
                        className="space-y-6"
                    >
                        {/* Info Cards */}
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                            {contactInfo.map((info, index) => (
                                <div
                                    key={index}
                                    className="bg-primary rounded-xl p-6 shadow-md"
                                >
                                    <div className="w-12 h-12 bg-primary/10 rounded-lg flex items-center justify-center mb-4">
                                        <info.icon size={24} className="text-primary" />
                                    </div>
                                    <h3 className="font-semibold mb-1">{info.title}</h3>
                                    <p className="text-secondary text-sm">{info.content}</p>
                                </div>
                            ))}
                        </div>

                        {/* Map Placeholder */}
                        <div className="bg-primary rounded-2xl overflow-hidden shadow-lg">
                            <div className="h-64 bg-gradient-to-br from-indigo-100 to-purple-100 flex items-center justify-center">
                                <div className="text-center">
                                    <MapPin size={48} className="mx-auto mb-2 text-indigo-600" />
                                    <p className="text-indigo-800 font-medium">Bản đồ</p>
                                    <p className="text-indigo-600 text-sm">123 Nguyễn Huệ, Q.1, TP.HCM</p>
                                </div>
                            </div>
                        </div>

                        {/* Social Links */}
                        <div className="bg-primary rounded-xl p-6 shadow-md">
                            <h3 className="font-semibold mb-4">{t('contactPage.socialTitle')}</h3>
                            <div className="flex gap-4">
                                {['Facebook', 'Zalo', 'Instagram', 'Youtube'].map((social) => (
                                    <button
                                        key={social}
                                        className="px-4 py-2 bg-secondary rounded-lg text-sm font-medium hover:bg-primary/10 transition-colors"
                                    >
                                        {social}
                                    </button>
                                ))}
                            </div>
                        </div>
                    </motion.div>
                </div>
            </div>
        </div>
    );
};

export default ContactPage;

import { useState, useEffect } from 'react';

import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { motion } from 'framer-motion';
import {
  ChevronRight,
  ArrowRight,
  Sparkles,
  Zap,
  Gift,
  TrendingUp,
  Loader2,
} from 'lucide-react';
import { ProductCard } from '@/components/common/ProductCard';
import SharedImage from '@/components/common/Image';
import { Button } from '@/components/ui';
import { useProducts, useCategories } from '@/hooks/useProducts';
import { useQuery } from '@tanstack/react-query';
import { promotionService, type Promotion } from '@/services/promotionService';

import { HOME_BANNERS, FLASH_SALE_TIMES } from '@/data/homeData';
import { formatCurrency } from '@/utils/format';
import { useBrands } from '@/hooks/useBrands';


// ============ Component ============



import { SectionHeader } from '@/components/common/SectionHeader';

// ============ Component ============

// ============ Home Page Component ============
export const HomePage = () => {
  const { t } = useTranslation();
  const [currentSlide, setCurrentSlide] = useState(0);

  // Fetch products from API
  const { data: productsData, isLoading } = useProducts({
    pageIndex: 1,
    pageSize: 20,
  });

  // Fetch categories from API
  const { data: categories = [], isLoading: loadingCategories } = useCategories();


  const { data: brandsData, isLoading: isLoadingBrands } = useBrands();
  const brandPartners = brandsData?.data?.items || [];

  const products = productsData?.products || [];

  const featuredProducts = products.slice(0, 8);
  const newProducts = products.slice(0, 4);
  // Fetch flash sales
  const { data: flashSales } = useQuery({
    queryKey: ['flash-sales'],
    queryFn: () => promotionService.getFlashSales(),
  });

  const flashSaleProductCodes = flashSales?.data?.flatMap((p: Promotion) => p.productCodes || []) || [];
  
  // Fetch flash sale products
  const { data: flashSaleProductsData } = useProducts({
      pageIndex: 1,
      pageSize: 20,
      ids: flashSaleProductCodes,
      enabled: flashSaleProductCodes.length > 0
  });

  const saleProducts = flashSaleProductsData?.products || [];

  // Countdown Timer Logic
  const [timeLeft, setTimeLeft] = useState<{hours: number, minutes: number, seconds: number}>({ hours: 0, minutes: 0, seconds: 0 });

  useEffect(() => {
    if (!flashSales?.data || flashSales.data.length === 0) return;
    
    // Find the soonest ending flash sale
    const activeFlashSale = flashSales.data?.find((p: Promotion) => p.isActive && new Date(p.endDate) > new Date());
    if(!activeFlashSale) return;

    const targetDate = new Date(activeFlashSale.endDate).getTime();

    const timer = setInterval(() => {
      const now = new Date().getTime();
      const distance = targetDate - now;

      if (distance < 0) {
        clearInterval(timer);
        return;
      }

      setTimeLeft({
        hours: Math.floor((distance / (1000 * 60 * 60))), // Total hours left
        minutes: Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60)),
        seconds: Math.floor((distance % (1000 * 60)) / 1000)
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [flashSales?.data]);

  // Auto slide
  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentSlide((prev) => (prev + 1) % HOME_BANNERS.length);
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div className="min-h-screen">
      {/* Hero Banner Slider */}
      <section className="relative h-[400px] md:h-[500px] lg:h-[600px] overflow-hidden">
        {HOME_BANNERS.map((banner, index) => (

          <motion.div
            key={banner.id}
            className={`absolute inset-0 ${index === currentSlide ? 'z-10' : 'z-0'}`}
            initial={{ opacity: 0 }}
            animate={{ opacity: index === currentSlide ? 1 : 0 }}
            transition={{ duration: 0.5 }}
          >
            {/* Background */}
            <div
              className="absolute inset-0 bg-cover bg-center"
              style={{ backgroundImage: `url(${banner.image})` }}
            />
            <div className="absolute inset-0 bg-gradient-to-r from-black/70 via-black/40 to-transparent" />

            {/* Content */}
            <div className="container mx-auto px-4 h-full flex items-center relative z-10">
              <div className="max-w-xl text-white">
                <motion.span
                  className="inline-flex items-center gap-2 px-4 py-2 bg-white/20 backdrop-blur-sm rounded-full text-sm font-semibold mb-4"
                  initial={{ y: 20, opacity: 0 }}
                  animate={{ y: 0, opacity: 1 }}
                  transition={{ delay: 0.2 }}
                >
                  <Sparkles size={16} />
                  {t(`home.banners.${banner.id}.subtitle`)}
                </motion.span>

                <motion.h1
                  className="text-3xl md:text-4xl lg:text-5xl font-extrabold mb-4"
                  initial={{ y: 30, opacity: 0 }}
                  animate={{ y: 0, opacity: 1 }}
                  transition={{ delay: 0.3 }}
                >
                  {t(`home.banners.${banner.id}.title`)}
                </motion.h1>

                <motion.p
                  className="text-lg md:text-xl opacity-90 mb-6"
                  initial={{ y: 30, opacity: 0 }}
                  animate={{ y: 0, opacity: 1 }}
                  transition={{ delay: 0.4 }}
                >
                  {t(`home.banners.${banner.id}.description`)}
                </motion.p>

                <motion.div
                  initial={{ y: 30, opacity: 0 }}
                  animate={{ y: 0, opacity: 1 }}
                  transition={{ delay: 0.5 }}
                >
                  <Link to={banner.link}>
                    <Button size="lg" rounded rightIcon={<ArrowRight size={20} />}>
                      {t(`home.banners.${banner.id}.cta`)}
                    </Button>
                  </Link>
                </motion.div>
              </div>
            </div>
          </motion.div>
        ))}

        {/* Dots */}
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex gap-2 z-20">
          {HOME_BANNERS.map((_, index) => (

            <button
              key={index}
              className={`w-3 h-3 rounded-full border-2 border-white transition-all ${index === currentSlide ? 'bg-white scale-110' : 'bg-transparent'
                }`}
              onClick={() => setCurrentSlide(index)}
            />
          ))}
        </div>
      </section>

      {/* Categories */}
      <section className="py-12 bg-secondary">
        <div className="container mx-auto px-4">
          <SectionHeader
            title={t('home.categories')}
            icon={<span className="text-2xl">🏷️</span>}
            viewAllLink="/products"

          />



          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4">
            {loadingCategories ? (
              Array.from({ length: 6 }).map((_, idx) => (
                <div key={idx} className="bg-primary rounded-xl p-4 flex flex-col items-center justify-center gap-3 animate-pulse">
                  <div className="w-24 h-24 bg-secondary/50 rounded-full" />
                  <div className="h-4 w-20 bg-secondary/50 rounded" />
                </div>
              ))
            ) : (
              categories.slice(0, 6).map((cat) => (
                <Link
                  key={cat.code}
                  to={`/products?category=${cat.code}`}
                  className="group bg-primary rounded-xl p-4 flex flex-col items-center justify-center gap-3 hover:shadow-lg transition-all border border-transparent hover:border-primary"
                >
                  <div className="w-24 h-24 rounded-full overflow-hidden bg-secondary/20 group-hover:scale-110 transition-transform">
                    <SharedImage
                      src={cat.imageURL}
                      alt={cat.name}
                      className="w-full h-full object-cover"
                    />
                  </div>
                  <div className="text-center">
                    <h3 className="font-semibold text-color-primary group-hover:text-primary transition-colors">
                      {cat.name}
                    </h3>
                  </div>
                </Link>
              )))}
          </div>

        </div>
      </section>

      {/* Flash Sale */}
      {/* Flash Sale - Only show if we have active sales */}
      {saleProducts.length > 0 && (
      <section className="py-12 bg-gradient-to-r from-gray-900 to-gray-800 text-white">
        <div className="container mx-auto px-4">
          <div className="flex flex-col md:flex-row items-center justify-between mb-6 gap-4">
            <div className="flex items-center gap-4">
              <Zap className="text-yellow-400 animate-pulse" size={28} />
              <h2 className="text-xl md:text-2xl font-bold">{t('shared.flashSale')}</h2>
              {/* Dynamic Countdown */}
              <div className="flex gap-2 font-mono text-lg font-bold">
                 <div className="bg-error px-2 py-1 rounded">{String(timeLeft.hours).padStart(2, '0')}</div>
                 <span className="self-center">:</span>
                 <div className="bg-error px-2 py-1 rounded">{String(timeLeft.minutes).padStart(2, '0')}</div>
                 <span className="self-center">:</span>
                 <div className="bg-error px-2 py-1 rounded">{String(timeLeft.seconds).padStart(2, '0')}</div>
              </div>
            </div>
            <Link
              to="/promotions"
              className="flex items-center gap-1 text-white/80 hover:text-white font-semibold transition-colors"
            >
              {t('common.viewAll')} <ChevronRight size={18} />
            </Link>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
            {saleProducts.map((product) => (
              <ProductCard key={product.code} product={product} />
            ))}
          </div>
        </div>
      </section>
      )}

      {/* Featured Products */}
      <section className="py-12">
        <div className="container mx-auto px-4">
          <SectionHeader
            title={t('home.featured')}
            icon={<span className="text-2xl">⭐</span>}
            viewAllLink="/products?featured=true"
          />

          {isLoading ? (
            <div className="flex items-center justify-center py-12">
              <Loader2 className="w-6 h-6 animate-spin text-accent" />
              <span className="ml-2 text-secondary">{t('common.loading')}</span>
            </div>
          ) : (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
              {featuredProducts.map((product) => (
                <ProductCard key={product.code} product={product} />
              ))}
            </div>
          )}
        </div>
      </section>

      {/* New Arrivals + Promo Banner */}
      <section className="py-12 bg-secondary">
        <div className="container mx-auto px-4">
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* New Arrivals */}
            <div className="lg:col-span-2">
              <SectionHeader
                title={t('home.newArrivals')}
                icon={<span className="text-2xl">🆕</span>}
                viewAllLink="/products?new=true"
              />
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {newProducts.map((product) => (
                  <ProductCard key={product.code} product={product} />
                ))}
              </div>
            </div>

            {/* Promo Banner */}
            <div className="relative bg-gradient-to-br from-primary to-purple-500 rounded-2xl overflow-hidden min-h-[400px] flex flex-col justify-end">
              <img
                src="https://images.unsplash.com/photo-1556909114-44e3e70034e2?w=400"
                alt="Promo"
                className="absolute inset-0 w-full h-full object-cover opacity-30"
              />
              <div className="relative z-10 p-6 text-white">
                <span className="inline-flex items-center gap-2 px-3 py-1 bg-white/20 rounded-full text-sm font-semibold mb-4">
                  <Gift size={16} />
                  {t('home.specialOffer')}
                </span>
                <h3 className="text-2xl font-bold mb-2">{t('home.registerMember')}</h3>
                <p className="opacity-90 mb-6">
                  {t('home.voucherOffer')}
                </p>
                <Link to="/register">
                  <Button className="bg-white text-primary hover:bg-gray-100">
                    {t('home.registerNow')} <ArrowRight size={18} />
                  </Button>
                </Link>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Best Sellers */}
      <section className="py-12">
        <div className="container mx-auto px-4">
          <SectionHeader
            title={t('home.bestSellers')}
            icon={<TrendingUp size={24} />}
            viewAllLink="/products?sort=bestseller"
          />

          <div className="space-y-4">
            {isLoading ? (
              <div className="flex items-center justify-center py-8">
                <Loader2 className="w-6 h-6 animate-spin text-accent" />
              </div>
            ) : (
              products.slice(0, 5).map((product, index) => (
                <Link
                  key={product.code}
                  to={`/product/${product.code}`}
                  className="flex items-center gap-4 p-4 bg-primary rounded-xl hover:shadow-lg hover:translate-x-1 transition-all"
                >
                  <span
