                <div className="text-primary font-medium">{product.code}</div>
                
                <div className="text-tertiary">{t('product.unit', 'Đơn vị tính')}:</div>
                <div className="text-primary">{product.baseUnit || t('product.defaultUnit', 'Cái')}</div>
                
                <div className="text-tertiary">{t('product.binLocation', 'Vị trí kho')}:</div>
                <div className="text-primary">{product.binLocation || t('common.updating', 'Đang cập nhật')}</div>
            </div>

            {/* Description */}
            <p className="text-secondary leading-relaxed line-clamp-3">{product.description}</p>

            {/* Dynamic Logistics Cards */}
            {product.details?.filter(d => d.detailType === ProductDetailType.LOGISTICS).length ? (
                <div className="flex flex-wrap gap-3 py-2">
                    {product.details.filter(d => d.detailType === ProductDetailType.LOGISTICS).map((detail, idx) => {
                        const lowerName = detail.specName.toLowerCase();
                        let Icon = Truck;
                        if (lowerName.includes('weight') || lowerName.includes('cân') || lowerName.includes('nặng') || lowerName.includes('kg')) Icon = Scale;
                        if (lowerName.includes('box') || lowerName.includes('hộp') || lowerName.includes('thùng') || lowerName.includes('pack') || lowerName.includes('quy cách')) Icon = Package;

                        return (
                            <div key={idx} className="flex items-center gap-2 p-3 bg-white border border-slate-100 rounded-xl shadow-sm">
                                <Icon size={16} className="text-indigo-500" />
                                <div className="text-xs">
                                    <span className="text-tertiary">{detail.specName}: </span>
                                    <span className="font-bold text-primary">{detail.specValue}</span>
                                </div>
                            </div>
                        );
                    })}
                    {product.countryOfOrigin && (
                        <div className="flex items-center gap-2 p-3 bg-white border border-slate-100 rounded-xl shadow-sm">
                            <Globe size={16} className="text-blue-500" />
                            <div className="text-xs">
                                <span className="text-tertiary">{t('product.origin', 'Xuất xứ')}: </span>
                                <span className="font-bold text-primary">{product.countryOfOrigin}</span>
                            </div>
                        </div>
                    )}
                </div>
            ) : null}

            {/* Quantity & Add to Cart */}
            {hasFixedPrice && (
              <div className="flex flex-col sm:flex-row gap-4">
                {/* Quantity */}
                <div className="flex items-center border rounded-lg bg-white">
                  <button
                    onClick={() => setQuantity(Math.max(1, quantity - 1))}
                    className="p-3 hover:bg-secondary transition-colors"
                  >
                    <Minus size={18} />
                  </button>
                  <span className="w-16 text-center font-semibold">{quantity}</span>
                  <button
                    onClick={() => setQuantity(Math.min(product.stockQuantity ?? product.stock, quantity + 1))}
                    disabled={quantity >= (product.stockQuantity ?? product.stock)}
                    className={`p-3 transition-colors ${quantity >= (product.stockQuantity ?? product.stock) ? 'opacity-50 cursor-not-allowed' : 'hover:bg-secondary'}`}
                  >
                    <Plus size={18} />
                  </button>
                </div>

                {/* Add to Cart */}
                <Button
                  size="lg"
                  className="flex-1 bg-slate-900 hover:bg-black text-white"
                  onClick={handleAddToCart}
                  disabled={(product.stockQuantity ?? product.stock) === 0 || isAddingToCart}
                  isLoading={isAddingToCart}
                  leftIcon={!isAddingToCart && <ShoppingCart size={20} />}
                >
                  {t('product.addToCart')}
                </Button>
              </div>
            )}

            {/* Contact for Quote */}
            {!hasFixedPrice && (
              <Link to={`/quote-request/${product.code}`}>
                <Button size="lg" fullWidth leftIcon={<Phone size={20} />}>
                  {t('product.requestQuote')}
                </Button>
              </Link>
            )}

            {/* Secondary Actions */}
            <div className="flex flex-wrap gap-3">
              <Button
                variant={isWishlisted ? 'primary' : 'outline'}
                onClick={handleWishlistToggle}
                leftIcon={<Heart size={18} fill={isWishlisted ? 'currentColor' : 'none'} />}
              >
                {isWishlisted ? t('product.inWishlist') : t('product.addToWishlist')}
              </Button>
              <Button
                variant={isCompared ? 'primary' : 'outline'}
                onClick={handleCompareToggle}
                leftIcon={<Scale size={18} />}
              >
                {t('product.compare')}
              </Button>
              <Button variant="ghost" leftIcon={<Share2 size={18} />}>
                {t('product.share')}
              </Button>
            </div>

            {/* Features */}
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 pt-4">
              {[
                { icon: Truck, title: t('product.freeShipping'), desc: t('product.freeShippingDesc') },
                { icon: Shield, title: t('product.warranty'), desc: t('product.warrantyDesc') },
                { icon: RefreshCw, title: t('product.returns'), desc: t('product.returnsDesc') },
              ].map((feature, i) => (
                <div key={i} className="flex items-start gap-3 p-3 bg-secondary rounded-lg">
                  <feature.icon size={20} className="text-primary flex-shrink-0 mt-0.5" />
                  <div>
                    <p className="font-medium text-sm">{feature.title}</p>
                    <p className="text-xs text-tertiary">{feature.desc}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="bg-primary rounded-xl p-6 mb-12">
          <div className="flex border-b mb-6 overflow-x-auto">
            {(['description', 'specs', 'units', 'variants', 'images', 'reviews'] as const).map((tab) => (
              <button
                key={tab}
                onClick={() => setActiveTab(tab)}
                className={`px-6 py-3 font-medium whitespace-nowrap transition-colors ${activeTab === tab
                    ? 'text-primary border-b-2 border-primary'
                    : 'text-secondary hover:text-primary'
                  }`}
              >
                {t(`product.tab.${tab}`)}
              </button>
            ))}
          </div>

          {/* Tab Content */}
          {activeTab === 'description' && (
            <div className="prose max-w-none">
              <p className="text-secondary leading-relaxed">{product.description}</p>
            </div>
          )}

          {activeTab === 'specs' && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-2">
              {product.details?.filter(d => d.detailType === ProductDetailType.SPEC).length ? (
                  product.details.filter(d => d.detailType === ProductDetailType.SPEC).map((detail, idx) => (
                     <div key={idx} className="flex border-b border-slate-100 py-3 text-sm">
                        <span className="w-1/2 font-medium text-secondary">{detail.specName}</span>
                        <span className="flex-1 text-primary font-semibold">{detail.specValue}</span>
                     </div>
                  ))
              ) : (
                  <div className="col-span-2 text-center py-8 text-tertiary">
                      {t('product.noSpecs', 'Không có thông số kỹ thuật chi tiết.')}
                  </div>
              )}
            </div>
          )}
          {activeTab === 'units' && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-2">
              {product.productUnits && product.productUnits.length ? (
                product.productUnits.map((unit, idx) => (
                  <div key={idx} className="flex border-b border-slate-100 py-3 text-sm">
                    <span className="w-1/2 font-medium text-secondary">{unit.unitName}</span>
                    <span className="flex-1 text-primary font-semibold">
                      {formatCurrency(unit.price)} (x{unit.conversionRate})
                    </span>
                  </div>
                ))
              ) : (
                <div className="col-span-2 text-center py-8 text-tertiary">
                  {t('product.noUnits', 'Không có thông tin đơn vị tính.')}
                </div>
              )}
            </div>
          )}

          {activeTab === 'variants' && (
            <div className="overflow-x-auto">
              {product.variants && product.variants.length ? (
                <table className="w-full text-sm text-left">
                  <thead className="bg-secondary/50 text-tertiary font-medium">
                    <tr>
                      <th className="px-4 py-3 border-b">{t('common.fields.code')}</th>
                      <th className="px-4 py-3 border-b">{t('common.fields.specs')}</th>
                      <th className="px-4 py-3 border-b text-right">{t('common.fields.price')}</th>
                      <th className="px-4 py-3 border-b text-right">{t('common.fields.stock')}</th>
                    </tr>
                  </thead>
                  <tbody>
                    {product.variants.map((v, idx) => (
                      <tr key={idx} className="border-b border-slate-50 hover:bg-secondary/20">
                        <td className="px-4 py-3 font-medium text-primary">{v.sku}</td>
                        <td className="px-4 py-3 text-secondary">{v.attributes}</td>
                        <td className="px-4 py-3 text-right font-bold text-error">{formatCurrency(v.price)}</td>
                        <td className="px-4 py-3 text-right text-secondary">{v.stockQuantity}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              ) : (
                <div className="text-center py-8 text-tertiary">
                  {t('product.noVariants', 'Không có phiên bản nào cho sản phẩm này.')}
                </div>
              )}
            </div>
          )}

          {activeTab === 'images' && (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-4">
              {images.length > 0 ? (
                images.map((img, idx) => (
                  <div 
                    key={idx} 
                    className="aspect-square rounded-xl overflow-hidden border border-slate-100 bg-white group cursor-zoom-in relative"
                    onClick={() => {
                        setSelectedIndex(idx);
                        setLightboxOpen(true);
                    }}
                  >
                    <SharedImage 
                      src={img} 
                      alt={`${product.name} gallery ${idx + 1}`} 
                      className="w-full h-full object-contain transition-transform group-hover:scale-110" 
                    />
                    <div className="absolute inset-0 bg-black/0 group-hover:bg-black/5 transition-colors" />
                  </div>
                ))
              ) : (
                <div className="col-span-full text-center py-12 text-secondary bg-secondary/30 rounded-xl">
                  {t('product.noImages', 'Không có hình ảnh nào.')}
                </div>
              )}
            </div>
          )}

          {activeTab === 'reviews' && (
            <div className="space-y-6">
              <div className="flex items-center justify-between bg-gradient-to-r from-indigo-50 to-purple-50 dark:from-indigo-900/20 dark:to-purple-900/20 p-4 rounded-xl">
                <div>
                  <h3 className="font-semibold text-lg text-slate-800 dark:text-slate-200">
                    {t('review.shareExperience', 'Chia sẻ trải nghiệm của bạn')}
                  </h3>
                  <p className="text-sm text-slate-500 dark:text-slate-400">
                    {t('review.helpOthers', 'Đánh giá của bạn sẽ giúp người khác tham khảo')}
                  </p>
                </div>
                <ProductReviewButton
                  productCode={product.code}
                  productName={product.name}
                  productImage={product.images?.[0]}
                  onReviewSubmitted={() => {
                    // Trigger refresh by forcing re-render
                    window.location.reload();
                  }}
                />
              </div>
              <ReviewsList productCode={product.code} />
            </div>
          )}
        </div>

        {/* Product Relations (Cross-selling) */}
        {relations.length > 0 && (
          <div className="mb-12">
            <h2 className="text-2xl font-bold mb-6 flex items-center gap-2">
                <RefreshCw className="text-indigo-500" size={24} />
                {t('product.frequentlyBoughtTogether', 'Thường được mua cùng (Phụ kiện)')}
            </h2>
            <div className="flex gap-4 overflow-x-auto pb-4 scrollbar-hide">
              {relations.map((rel, idx) => (
                <Link 
                    key={idx}
                    to={`/products?search=${encodeURIComponent(rel.specValue)}`}
                    className="flex-shrink-0"
                >
                    <Button variant="outline" className="h-auto py-3 px-6 rounded-2xl border-indigo-100 hover:border-indigo-500 hover:bg-indigo-50 transition-all flex flex-col items-center gap-1 group">
                        <span className="text-xs text-tertiary">{t('product.suggestion', 'Gợi ý')}:</span>
                        <span className="font-bold text-indigo-600 group-hover:scale-105 transition-transform">{rel.specValue}</span>
                    </Button>
                </Link>
              ))}
            </div>
          </div>
        )}

        {/* Related Products */}
        {relatedProducts.length > 0 && (
          <div>
            <h2 className="text-2xl font-bold mb-6">{t('product.relatedProducts')}</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
              {relatedProducts.map((p) => (
                <ProductCard key={p.code} product={p} />
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default ProductDetailPage;

import { useState, useMemo, useCallback, memo } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Grid,
  List,
  SlidersHorizontal,
  ChevronDown,
  ChevronRight,
  Star,
  Loader2,
  AlertCircle,
  Search,
} from 'lucide-react';
import { ProductCard } from '@/components/common/ProductCard';
import { ProductSkeleton } from '@/components/common/ProductSkeleton';
import { Button, Badge } from '@/components/ui';
import { useDebounce, useProducts, useCategories } from '@/hooks';

import type { CategoryDto } from '@/services/productService';

// ============ Filter Sidebar Component ============
interface FilterSidebarProps {
  categories: CategoryDto[];
  selectedCategories: string[];
  onCategoryToggle: (code: string) => void;
  selectedBrands: string[];
  onBrandToggle: (brand: string) => void;
  priceRange: [number, number];
  onPriceRangeChange: (range: [number, number]) => void;
  priceType: 'all' | 'fixed' | 'contact';
  onPriceTypeChange: (type: 'all' | 'fixed' | 'contact') => void;
  selectedRating: number | null;
  onRatingChange: (rating: number | null) => void;
  brands: string[];
  onClearAll: () => void;
  hasActiveFilters: boolean;
}

const FilterSidebar = memo(({
  categories,
  selectedCategories,
  onCategoryToggle,
  selectedBrands,
  onBrandToggle,
  priceRange,
  onPriceRangeChange,
  priceType,
  onPriceTypeChange,
  selectedRating,
  onRatingChange,
  brands,
  onClearAll,
  hasActiveFilters,
}: FilterSidebarProps) => {
  const { t } = useTranslation();

  const priceShortcuts = [
    { label: t('filter.priceUnder1M'), range: [0, 1000000] as [number, number] },
    { label: t('filter.price1to5M'), range: [1000000, 5000000] as [number, number] },
    { label: t('filter.price5to10M'), range: [5000000, 10000000] as [number, number] },
    { label: t('filter.priceOver10M'), range: [10000000, 100000000] as [number, number] },
  ];

  return (
    <aside className="w-80 bg-primary rounded-xl p-4 h-fit sticky top-24 border shadow-sm z-10 shrink-0">
      <div className="flex justify-between items-center mb-4 pb-3 border-b">
        <h3 className="flex items-center gap-2 font-semibold text-primary">
          <SlidersHorizontal size={18} />
          {t('filter.title')}
        </h3>
        {hasActiveFilters && (
          <button onClick={onClearAll} className="text-sm text-error hover:underline">
            {t('filter.clearAll')}
          </button>
        )}
      </div>

      {/* Categories */}
      <div className="mb-6">
        <h4 className="text-sm font-semibold mb-3">{t('filter.category')}</h4>
        <div className="space-y-2 max-h-48 overflow-y-auto custom-scrollbar pr-1">
          {categories.map((cat) => (
            <div
              key={cat.code}
              onClick={() => onCategoryToggle(cat.code)}
              className="flex items-center gap-3 cursor-pointer group"
            >
              <span
                className={`w-4 h-4 rounded border-2 flex items-center justify-center transition-colors ${selectedCategories.includes(cat.code) ? 'border-primary bg-accent-primary' : 'border-tertiary'
                  }`}
              >
                {selectedCategories.includes(cat.code) && (
                  <svg viewBox="0 0 12 9" className="w-2.5 h-2.5 text-white" fill="none" stroke="currentColor" strokeWidth="2">
                    <path d="M1 4L4.5 7.5L11 1" />
                  </svg>
                )}
              </span>
              <span className="flex-1 text-sm text-secondary group-hover:text-primary transition-colors">
                {cat.name}
              </span>
              {/* Product count not available in API yet */}
              {/* <span className="text-xs text-tertiary bg-secondary px-1.5 py-0.5 rounded">
                {cat.productCount}
              </span> */}
            </div>
          ))}
          {categories.length === 0 && (
            <div className="text-sm text-tertiary italic">{t('common.noCategories')}</div>
          )}
        </div>
      </div>

      {/* Price Type */}
      <div className="mb-6">
        <h4 className="text-sm font-semibold mb-3">{t('filter.priceType')}</h4>
        <div className="space-y-2">
          {(['all', 'fixed', 'contact'] as const).map((type) => (
            <div
              key={type}
              onClick={() => onPriceTypeChange(type)}
              className="flex items-center gap-3 cursor-pointer group"
            >
              <span className={`w-4 h-4 rounded-full border-2 flex items-center justify-center transition-colors ${priceType === type ? 'border-primary bg-accent-primary' : 'border-tertiary'
                }`}>
                {priceType === type && <span className="w-1.5 h-1.5 bg-white rounded-full" />}
              </span>
              <span className="text-sm text-secondary group-hover:text-primary transition-colors">
                {type === 'all' ? t('common.all') : type === 'fixed' ? t('filter.fixedPrice') : t('filter.contactPrice')}
              </span>
            </div>
          ))}
        </div>
      </div>

      {/* Price Range */}
      <div className="mb-6">
        <h4 className="text-sm font-semibold mb-3">{t('filter.priceRange')}</h4>
        <div className="flex gap-2 mb-3">
          <input
            type="number"
            placeholder={t('filter.from')}
            value={priceRange[0] || ''}
            onChange={(e) => onPriceRangeChange([Number(e.target.value) || 0, priceRange[1]])}
            className="flex-1 w-full min-w-0 px-2 py-2 border rounded-lg text-sm text-center focus:outline-none focus:border-primary"
          />
          <span className="self-center text-tertiary">-</span>
          <input
            type="number"
            placeholder={t('filter.to')}
            value={priceRange[1] === 100000000 ? '' : priceRange[1]}
            onChange={(e) => onPriceRangeChange([priceRange[0], Number(e.target.value) || 100000000])}
            className="flex-1 w-full min-w-0 px-2 py-2 border rounded-lg text-sm text-center focus:outline-none focus:border-primary"
          />
        </div>
        <div className="flex flex-wrap gap-2">
          {priceShortcuts.map((s) => (
            <button
              key={s.label}
              onClick={() => onPriceRangeChange(s.range)}
              className={`px-2 py-1 text-xs border rounded-lg transition-colors ${priceRange[0] === s.range[0] && priceRange[1] === s.range[1]
                ? 'bg-accent-primary text-white border-primary'
                : 'border-tertiary text-secondary hover:border-primary'
                }`}
            >
              {s.label}
            </button>
          ))}
        </div>
      </div>

      {/* Brands */}
      <div className="mb-6">
        <h4 className="text-sm font-semibold mb-3">{t('filter.brand')}</h4>
        <div className="space-y-2">
          {brands.map((brand) => (
            <div
              key={brand}
              onClick={() => onBrandToggle(brand)}
              className="flex items-center gap-3 cursor-pointer group"
            >
              <span
                className={`w-4 h-4 rounded border-2 flex items-center justify-center transition-colors ${selectedBrands.includes(brand) ? 'border-primary bg-accent-primary' : 'border-tertiary'
                  }`}
              >
                {selectedBrands.includes(brand) && (
                  <svg viewBox="0 0 12 9" className="w-2.5 h-2.5 text-white" fill="none" stroke="currentColor" strokeWidth="2">
                    <path d="M1 4L4.5 7.5L11 1" />
                  </svg>
                )}
              </span>
              <span className="text-sm text-secondary group-hover:text-primary transition-colors">
                {brand}
              </span>
            </div>
          ))}
        </div>
      </div>

      {/* Rating */}
      <div>
        <h4 className="text-sm font-semibold mb-3">{t('filter.rating')}</h4>
        <div className="space-y-2">
          {[5, 4, 3, 2, 1].map((rating) => (
            <button
              key={rating}
              onClick={() => onRatingChange(selectedRating === rating ? null : rating)}
              className={`flex items-center gap-2 w-full px-2 py-1.5 rounded-lg text-xs transition-colors ${selectedRating === rating ? 'bg-indigo-50 dark:bg-indigo-900/30 text-accent' : 'hover:bg-tertiary'
                }`}
            >
              {Array.from({ length: 5 }).map((_, i) => (
                <Star
                  key={i}
                  size={12}
                  className={i < rating ? 'text-yellow-400 fill-yellow-400' : 'text-gray-300'}
                />
              ))}
              <span className="text-secondary">{t('filter.ratingUp')}</span>
            </button>
          ))}
        </div>
      </div>
    </aside>
  );
});

FilterSidebar.displayName = 'FilterSidebar';

// ============ Products Page Component ============
export const ProductsPage = () => {
  const { t } = useTranslation();
  const [searchParams, setSearchParams] = useSearchParams();
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [showFilters, setShowFilters] = useState(true);
  const [sortBy, setSortBy] = useState('newest');
  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 12;

  // Filters state
  const [priceRange, setPriceRange] = useState<[number, number]>([0, 100000000]); // Filter States
  const [selectedCategories, setSelectedCategories] = useState<string[]>(
    searchParams.get('category') ? searchParams.get('category')!.split(',') : []
  );
  const [selectedBrands, setSelectedBrands] = useState<string[]>([]);
  const [selectedRating, setSelectedRating] = useState<number | null>(null);
  const [priceType, setPriceType] = useState<'all' | 'fixed' | 'contact'>('all');

  const searchQuery = searchParams.get('search') || '';
  const categorySlug = searchParams.get('category') || '';
  const debouncedSearch = useDebounce(searchQuery, 300);

  // Map sortBy to API format
  const getSortConfig = () => {
    switch (sortBy) {
      case 'price-asc':
        return { field: 'price', dir: 'asc' as const };
      case 'price-desc':
        return { field: 'price', dir: 'desc' as const };
      case 'newest':
      default:
        return { field: 'createdAt', dir: 'desc' as const };
    }
  };

  // Fetch products from API
  const sortConfig = getSortConfig();
  // Fetch Categories
  const { data: categories = [] } = useCategories();

  // Fetch Products
  const {
    data: productsData,
    isLoading,
    isError,
    error,
  } = useProducts({
    pageIndex: currentPage,
    pageSize,
    search: debouncedSearch || undefined,
    sortField: sortConfig.field,
    sortDir: sortConfig.dir,
    category: categorySlug,
    brands: selectedBrands,   // Pass to API (even if backend doesn't support it yet, hook handles it)
    minPrice: priceRange[0], // Server-side Price Filter
    maxPrice: priceRange[1], // Server-side Price Filter
    rating: selectedRating || undefined, // Pass to API
    priceType: priceType, // Pass Price Type to API
  });

  // Get unique brands from fetched products
  const brands = useMemo(() => {
    const brandSet = new Set(
      (productsData?.products || []).map((p) => p.brand).filter(Boolean)
    );
    return Array.from(brandSet) as string[];
  }, [productsData?.products]);

  // Apply client-side logic for features NOT supported by API yet
  // Currently: None (if Generic Search handles everything via 'In' or property checks)
  // However, since Brand/Rating are mocked on FE, passing them to API might return empty or error if fields don't exist.
  // QueryHelper uses reflection. If 'Brand' doesn't exist on TblProduct, it skips. UseProducts will send it.
  // Result: API returns ALL products (filter ignored). FE must filter client-side for these mocked fields.
  const filteredProducts = useMemo(() => {
    let products = [...(productsData?.products || [])];

    // Client-side filtering for Multi-Category (if passed as separate params or single param in URL)
    // Controller logic handles "category" param. 
    // If selectedCategories has content, it overrides categorySlug.
    if (selectedCategories.length > 0) {
      // Logic handled by API "category" param which we set in URL?
      // Wait, selectedCategories updates URL 'category'.
      // So API receives it.
      // But we might have latency or mismatch.
      // Actually, if we trust API, we don't need this.
      // products = products.filter((p) => selectedCategories.includes(p.categoryId));
    }

    // Client-side Brand (Mock Validation)
    if (selectedBrands.length > 0) {
       // Since backend might ignore 'Brand' if missing, we filter here to be safe for Mock UI
       products = products.filter((p) => p.brand && selectedBrands.includes(p.brand));
    }

    // Price is now Server-Side. Remove client filter.

    if (selectedRating) {
       // Since backend might ignore 'Rating', and data is mocked
       products = products.filter((p) => (p.rating || 0) >= selectedRating);
    }

    // Client-side sorting for rating/bestseller (not supported by API)
    switch (sortBy) {
      case 'rating':
        products.sort((a, b) => (b.rating || 0) - (a.rating || 0));
        break;
      case 'bestseller':
        products.sort((a, b) => (b.reviewCount || 0) - (a.reviewCount || 0));
        break;
    }

    return products;
  }, [productsData?.products, categorySlug, selectedCategories, selectedBrands, priceRange, priceType, selectedRating, sortBy]);

  // Handlers
  const handleCategoryToggle = useCallback((id: string) => {
    setSelectedCategories((prev) => {
      const next = prev.includes(id)
        ? prev.filter((c) => c !== id)
        : [...prev, id];

      // Optional: Update URL to reflect single category selection (common pattern)
      // If we want multi-select in URL, we'd join them. For now let's assume single or primary category in URL
      if (next.length > 0) {
        setSearchParams(params => {
          params.set('category', next.join(',')); // Join with comma for multiple selection
          return params;
        });
      } else {
        setSearchParams(params => {
          params.delete('category');
          return params;
        });
      }
      return next;
    });
    setCurrentPage(1);
  }, [setSearchParams]);

  const handleBrandToggle = useCallback((brand: string) => {
    setSelectedBrands((prev) =>
      prev.includes(brand) ? prev.filter((b) => b !== brand) : [...prev, brand]
    );
  }, []);

  const clearFilters = useCallback(() => {
    setSelectedCategories([]);
    setSelectedBrands([]);
    setPriceRange([0, 100000000]);
    setSelectedRating(null);
    setPriceType('all');
    setSearchParams({});
  }, [setSearchParams]);

  const hasActiveFilters =
    selectedCategories.length > 0 ||
    selectedBrands.length > 0 ||
    selectedRating !== null ||
    priceType !== 'all' ||
    priceRange[0] > 0 ||
    priceRange[1] < 100000000;

  return (
    <div className="min-h-screen bg-secondary">
      {/* Breadcrumb */}
      <div className="bg-primary border-b py-3">
        <div className="container mx-auto px-4 flex items-center gap-2 text-sm">
          <Link to="/" className="text-secondary hover:text-accent transition-colors">
            {t('common.home')}
          </Link>
          <ChevronRight size={14} className="text-tertiary" />
          <span className="text-primary font-medium">{t('common.products')}</span>
          {categorySlug && (
            <>
              <ChevronRight size={14} className="text-tertiary" />
              <span className="text-primary font-medium">
                {categories.find((c) => c.code === categorySlug)?.name || categorySlug}
              </span>
            </>
          )}
        </div>
      </div>

      <div className="container mx-auto px-4 py-6">
        <div className="flex gap-6">
          {/* Filters */}
          <AnimatePresence>
            {showFilters && (
              <motion.div
                initial={{ x: -20, opacity: 0 }}
                animate={{ x: 0, opacity: 1 }}
                exit={{ x: -20, opacity: 0 }}
                className="hidden lg:block"
              >
                <FilterSidebar
                  categories={categories}
                  selectedCategories={selectedCategories}
                  onCategoryToggle={handleCategoryToggle}
                  selectedBrands={selectedBrands}
                  onBrandToggle={handleBrandToggle}
                  priceRange={priceRange}
                  onPriceRangeChange={setPriceRange}
                  priceType={priceType}
                  onPriceTypeChange={setPriceType}
                  selectedRating={selectedRating}
                  onRatingChange={setSelectedRating}
                  brands={brands}
                  onClearAll={clearFilters}
                  hasActiveFilters={hasActiveFilters}
                />
              </motion.div>
            )}
          </AnimatePresence>

          {/* Products */}
          <div className="flex-1">
            {/* Toolbar */}
            <div className="flex justify-between items-center p-4 bg-primary rounded-xl mb-6 border shadow-sm">
              <div className="flex items-center gap-4">
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setShowFilters(!showFilters)}
                  leftIcon={<SlidersHorizontal size={18} />}
                  className="hidden lg:flex"
                >
                  {showFilters ? t('filter.hideFilter') : t('filter.showFilter')}
                </Button>

                {/* Search Input */}
                <div className="relative flex-1 max-w-xs">
                  <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-tertiary" />
                  <input
                    type="text"
                    placeholder={t('common.search')}
                    value={searchParams.get('search') || ''}
                    onChange={(e) => {
                      const newParams = new URLSearchParams(searchParams);
                      if (e.target.value) {
                        newParams.set('search', e.target.value);
                      } else {
                        newParams.delete('search');
                      }
                      setSearchParams(newParams);
                    }}
                    className="w-full pl-10 pr-4 py-2 border rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 bg-secondary"
                  />
                </div>

                <span className="text-sm text-secondary">
                  {t('filter.showResults', { count: filteredProducts.length })}
                </span>
              </div>

              <div className="flex items-center gap-4">
                {/* Sort */}
                <div className="relative flex items-center gap-2">
                  <span className="text-sm text-secondary hidden sm:inline">{t('filter.sortBy')}:</span>
                  <select
                    value={sortBy}
                    onChange={(e) => setSortBy(e.target.value)}
                    className="appearance-none px-4 py-2 pr-8 border rounded-lg text-sm focus:outline-none focus:border-primary cursor-pointer"
                  >
                    <option value="newest">{t('filter.newest')}</option>
                    <option value="price-asc">{t('filter.priceAsc')}</option>
                    <option value="price-desc">{t('filter.priceDesc')}</option>
                    <option value="rating">{t('filter.topRated')}</option>
                    <option value="bestseller">{t('filter.bestSeller')}</option>
                  </select>
                  <ChevronDown size={16} className="absolute right-2 text-tertiary pointer-events-none" />
                </div>

                {/* View Toggle */}
                <div className="flex border rounded-lg overflow-hidden">
                  <button
                    onClick={() => setViewMode('grid')}
                    className={`p-2 transition-colors ${viewMode === 'grid' ? 'bg-accent-primary text-white' : 'hover:bg-tertiary'
                      }`}
                  >
                    <Grid size={18} />
                  </button>
                  <button
                    onClick={() => setViewMode('list')}
                    className={`p-2 transition-colors ${viewMode === 'list' ? 'bg-accent-primary text-white' : 'hover:bg-tertiary'
                      }`}
                  >
                    <List size={18} />
                  </button>
                </div>
              </div>
            </div>

            {/* Active Filters */}
            {hasActiveFilters && (
              <div className="flex flex-wrap gap-2 mb-6">
                {selectedCategories.map((catId) => {
                  const cat = categories.find((c) => c.code === catId);
                  return (
                    <Badge
                      key={catId}
                      color="primary"
                      variant="soft"
                      closable
                      onClose={() => handleCategoryToggle(catId)}
                    >
                      {cat?.name}
                    </Badge>
                  );
                })}
                {selectedBrands.map((brand) => (
                  <Badge
                    key={brand}
                    color="primary"
                    variant="soft"
                    closable
                    onClose={() => handleBrandToggle(brand)}
                  >
                    {brand}
                  </Badge>
                ))}
                {priceType !== 'all' && (
                  <Badge
                    color="primary"
                    variant="soft"
                    closable
                    onClose={() => setPriceType('all')}
                  >
                    {priceType === 'fixed' ? t('filter.fixedPrice') : t('filter.contactPrice')}
                  </Badge>
                )}
              </div>
            )}

            {/* Products Grid */}
            {isLoading ? (
              <div
                className={`grid gap-6 ${viewMode === 'list'
                  ? 'grid-cols-1'
                  : 'grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-4'
                  }`}
              >
                {Array.from({ length: pageSize }).map((_, i) => (
                  <div key={i} className="h-[400px]">
                    <ProductSkeleton />
                  </div>
                ))}
              </div>
            ) : isError ? (
              <div className="text-center py-16 bg-primary rounded-xl">
                <AlertCircle className="w-12 h-12 mx-auto mb-4 text-red-500" />
                <h3 className="text-xl font-semibold mb-2">{t('common.errorOccurred')}</h3>
                <p className="text-secondary mb-6">
                  {error instanceof Error ? error.message : t('common.loadError')}
                </p>
                <Button onClick={() => window.location.reload()}>{t('common.retry')}</Button>
              </div>
            ) : filteredProducts.length > 0 ? (
              <div
                className={`grid gap-6 ${viewMode === 'list'
                  ? 'grid-cols-1'
                  : 'grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-4'
                  }`}
              >
                {filteredProducts.map((product) => (
                  <ProductCard
                    key={product.code}
                    product={product}
                    variant={viewMode === 'list' ? 'list' : 'grid'}
                  />
                ))}
              </div>
            ) : (
              <div className="text-center py-16 bg-primary rounded-xl">
                <div className="text-6xl mb-4">🔍</div>
                <h3 className="text-xl font-semibold mb-2">{t('common.noResults')}</h3>
                <p className="text-secondary mb-6">{t('common.noResultsHint')}</p>
                <Button onClick={clearFilters}>{t('filter.clearAll')}</Button>
              </div>
            )}

            {/* Pagination */}
            {!isLoading && productsData && productsData.totalPages > 1 && (
              <div className="flex justify-center gap-2 mt-8">
                <button
                  onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
                  disabled={!productsData.hasPreviousPage}
                  className="w-10 h-10 flex items-center justify-center border rounded-lg text-secondary hover:border-primary disabled:opacity-50"
                >
                  ‹
                </button>
                {Array.from({ length: Math.min(5, productsData.totalPages) }, (_, i) => {
                  const pageNum = i + 1;
                  return (
                    <button
                      key={pageNum}
                      onClick={() => setCurrentPage(pageNum)}
                      className={`w-10 h-10 flex items-center justify-center border rounded-lg font-medium transition-colors ${currentPage === pageNum
                        ? 'bg-accent-primary text-white border-primary'
                        : 'hover:border-primary'
                        }`}
                    >
                      {pageNum}
                    </button>
                  );
                })}
                {productsData.totalPages > 5 && (
                  <>
                    <span className="w-10 h-10 flex items-center justify-center text-tertiary">...</span>
                    <button
                      onClick={() => setCurrentPage(productsData.totalPages)}
                      className={`w-10 h-10 flex items-center justify-center border rounded-lg ${currentPage === productsData.totalPages
                        ? 'bg-accent-primary text-white border-primary'
                        : 'hover:border-primary'
                        }`}
                    >
                      {productsData.totalPages}
                    </button>
                  </>
                )}
                <button
                  onClick={() => setCurrentPage((p) => Math.min(productsData.totalPages, p + 1))}
                  disabled={!productsData.hasNextPage}
                  className="w-10 h-10 flex items-center justify-center border rounded-lg text-secondary hover:border-primary disabled:opacity-50"
                >
                  ›
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductsPage;

import { useState, useMemo, useCallback } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import {
  ChevronRight,
  Search,
  SlidersHorizontal,
  Grid,
  List,
  AlertCircle
} from 'lucide-react';
import { ProductCard } from '@/components/common/ProductCard';
import { ProductSkeleton } from '@/components/common/ProductSkeleton';
import { Button } from '@/components/ui';
import { useDebounce, useProducts } from '@/hooks';

const SearchPage = () => {
  const { t } = useTranslation();
  const [searchParams, setSearchParams] = useSearchParams();
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 12;

  const searchQuery = searchParams.get('search') || '';
  const debouncedSearch = useDebounce(searchQuery, 300);

  const {
    data: productsData,
    isLoading,
    isError,
    error,
  } = useProducts({
    pageIndex: currentPage,
    pageSize,
    search: debouncedSearch || undefined,
  });

  const products = productsData?.products || [];

  return (
    <div className="min-h-screen bg-secondary">
      {/* Breadcrumb */}
      <div className="bg-primary border-b py-3">
        <div className="container mx-auto px-4 flex items-center gap-2 text-sm">
          <Link to="/" className="text-secondary hover:text-accent transition-colors">
            {t('common.home')}
          </Link>
          <ChevronRight size={14} className="text-tertiary" />
          <span className="text-primary font-medium">{t('common.search')}</span>
        </div>
      </div>

      <div className="container mx-auto px-4 py-8">
        <div className="flex flex-col gap-8">
          {/* Search Info & Bar */}
          <div className="bg-primary rounded-2xl p-6 border shadow-sm">
            <h1 className="text-2xl font-bold mb-6 flex items-center gap-3">
              <Search className="text-accent-primary" />
              {searchQuery ? (
                <span>{t('search.resultsFor') || 'Search results for'}: <span className="text-accent-primary">&quot;{searchQuery}&quot;</span></span>
              ) : (
                <span>{t('header.searchPlaceholder')}</span>
              )}
            </h1>

            <div className="flex flex-col md:flex-row gap-4 items-center">
              <div className="relative flex-1 w-full">
                <Search size={20} className="absolute left-4 top-1/2 -translate-y-1/2 text-tertiary" />
                <input
                  type="text"
                  value={searchQuery}
                  onChange={(e) => {
                    const params = new URLSearchParams(searchParams);
                    if (e.target.value) params.set('search', e.target.value);
                    else params.delete('search');
                    setSearchParams(params);
                  }}
                  placeholder={t('header.searchPlaceholder')}
                  className="w-full pl-12 pr-4 py-3 bg-secondary border border-transparent focus:border-indigo-500 rounded-xl outline-none transition-all"
                />
              </div>
              <div className="flex border rounded-xl overflow-hidden shrink-0">
                <button
                  onClick={() => setViewMode('grid')}
                  className={`p-3 transition-colors ${viewMode === 'grid' ? 'bg-indigo-600 text-white' : 'bg-primary hover:bg-secondary'}`}
                >
                  <Grid size={20} />
                </button>
                <button
                  onClick={() => setViewMode('list')}
                  className={`p-3 transition-colors ${viewMode === 'list' ? 'bg-indigo-600 text-white' : 'bg-primary hover:bg-secondary'}`}
                >
                  <List size={20} />
                </button>
              </div>
            </div>
          </div>

          {/* Results Area */}
          <div>
            {isLoading ? (
              <div className={`grid gap-6 ${viewMode === 'list' ? 'grid-cols-1' : 'grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4'}`}>
                {Array.from({ length: 8 }).map((_, i) => (
                  <ProductSkeleton key={i} />
                ))}
              </div>
            ) : isError ? (
              <div className="text-center py-20 bg-primary rounded-2xl border">
                <AlertCircle className="w-16 h-16 mx-auto mb-4 text-red-500" />
                <h2 className="text-xl font-bold mb-2">{t('common.errorOccurred')}</h2>
                <p className="text-secondary mb-6">{error instanceof Error ? error.message : t('common.loadError')}</p>
                <Button onClick={() => window.location.reload()}>{t('common.retry')}</Button>
              </div>
            ) : products.length > 0 ? (
              <div className={`grid gap-6 ${viewMode === 'list' ? 'grid-cols-1' : 'grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4'}`}>
                {products.map((product) => (
                  <ProductCard key={product.code} product={product} variant={viewMode === 'list' ? 'list' : 'grid'} />
                ))}
              </div>
            ) : (
              <div className="text-center py-20 bg-primary rounded-2xl border shadow-sm">
                <div className="text-7xl mb-6">🔍</div>
                <h2 className="text-2xl font-bold mb-2">{t('common.noResults')}</h2>
                <p className="text-secondary max-w-md mx-auto">
                  {t('common.noResultsHint') || "We couldn't find any products matching your search query. Please try different keywords."}
                </p>
                <Button variant="outline" className="mt-8" onClick={() => setSearchParams({})}>
                  {t('filter.clearAll')}
                </Button>
              </div>
            )}

            {/* Pagination */}
            {!isLoading && productsData && productsData.totalPages > 1 && (
              <div className="flex justify-center gap-2 mt-12">
                <button
                  onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
                  disabled={!productsData.hasPreviousPage}
                  className="w-12 h-12 flex items-center justify-center border rounded-xl bg-primary text-secondary disabled:opacity-50"
                >
                  ‹
                </button>
                {Array.from({ length: productsData.totalPages }, (_, i) => i + 1).map((pageNum) => (
                  <button
                    key={pageNum}
                    onClick={() => setCurrentPage(pageNum)}
                    className={`w-12 h-12 flex items-center justify-center border rounded-xl font-bold transition-all ${currentPage === pageNum ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg scale-110' : 'bg-primary hover:border-indigo-400'}`}
                  >
                    {pageNum}
                  </button>
                ))}
                <button
                  onClick={() => setCurrentPage((p) => Math.min(productsData.totalPages, p + 1))}
                  disabled={!productsData.hasNextPage}
                  className="w-12 h-12 flex items-center justify-center border rounded-xl bg-primary text-secondary disabled:opacity-50"
                >
                  ›
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default SearchPage;

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { motion } from 'framer-motion';
import {
    HelpCircle, MessageCircle, Phone, Mail, FileText,
    ChevronDown, ChevronUp, Package, CreditCard, Truck, RefreshCw
