                            >
                                <cat.icon className="mx-auto mb-3 text-indigo-600" size={32} />
                                <p className="font-medium">{cat.title}</p>
                            </Link>
                        </motion.div>
                    ))}
                </div>

                <div className="grid lg:grid-cols-2 gap-12">
                    {/* FAQs */}
                    <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }}>
