interface SettingsState {
    emailNotif: boolean;
    orderNotif: boolean;
    promoNotif: boolean;
    darkMode: boolean;
    language: string;
}

export const SettingsContent = () => {
    const { t, i18n } = useTranslation();
    const toast = useToast();
    const [loading, setLoading] = useState(false);
    
    // Preferences State
    const [settings, setSettings] = useState<SettingsState>(() => {
        const defaults = {
            emailNotif: true,
            orderNotif: true,
            promoNotif: true,
            darkMode: false,
            language: 'vi'
        };
        const saved = localStorage.getItem('user_settings');
        if (saved) {
            try {
                return { ...defaults, ...JSON.parse(saved) };
            } catch (e) { 
                console.error('Failed to parse settings', e); 
                return defaults;
            }
        }
        return defaults;
    });

    const handleSave = () => {
        setLoading(true);
        // Simulate API call
        setTimeout(() => {
            localStorage.setItem('user_settings', JSON.stringify(settings));
            // Apply side effects
            if (settings.language !== i18n.language) {
                i18n.changeLanguage(settings.language);
            }
            // Dark mode toggle would go here if implemented globally
            
            toast.success(t('settings.updateSuccess'));
            setLoading(false);
        }, 800);
    };

    return (
        <div className="space-y-6">
            <div className="bg-primary rounded-xl p-6 border shadow-sm">
                <h2 className="text-xl font-bold mb-6">{t('account.settings')}</h2>
                
                <div className="space-y-8">
                    {/* Notifications Group */}
                    <div>
                        <h3 className="font-semibold mb-4 text-primary flex items-center gap-2">
                            <Bell size={18} /> {t('settings.notifications')}
                        </h3>
                        <div className="space-y-4 bg-secondary/50 p-4 rounded-xl border border-secondary/20">
                            <Switch
                                label={t('settings.orderNotif')}
                                description={t('settings.orderNotifDesc')}
                                checked={settings.orderNotif}
                                onChange={(v) => setSettings(s => ({ ...s, orderNotif: v }))}
                            />
                            <div className="h-px bg-secondary/10" />
                            <Switch
                                label={t('settings.promoNotif')}
                                description={t('settings.promoNotifDesc')}
                                checked={settings.emailNotif}
                                onChange={(v) => setSettings(s => ({ ...s, emailNotif: v }))}
                            />
                        </div>
                    </div>

                    {/* App Preferences */}
                    <div>
                        <h3 className="font-semibold mb-4 text-primary flex items-center gap-2">
                            <Globe size={18} /> {t('settings.preferences')}
                        </h3>
                        <div className="space-y-4 bg-secondary/50 p-4 rounded-xl border border-secondary/20">
                            <div className="flex items-center justify-between">
                                <div>
                                    <p className="font-medium">{t('settings.language')}</p>
                                    <p className="text-xs text-secondary">{t('settings.languageDesc')}</p>
                                </div>
                                <div className="flex gap-2">
                                    <button 
                                        onClick={() => setSettings(s => ({ ...s, language: 'vi' }))}
                                        className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${settings.language === 'vi' ? 'bg-primary text-white shadow-sm' : 'bg-secondary text-secondary hover:bg-secondary/80'}`}
                                    >
                                        {t('settings.vietnamese')}
                                    </button>
                                    <button 
                                        onClick={() => setSettings(s => ({ ...s, language: 'en' }))}
                                        className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${settings.language === 'en' ? 'bg-primary text-white shadow-sm' : 'bg-secondary text-secondary hover:bg-secondary/80'}`}
                                    >
                                        {t('settings.english')}
                                    </button>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="flex justify-end pt-4">
                        <Button onClick={handleSave} isLoading={loading}>
                            {t('settings.saveChanges')}
                        </Button>
                    </div>
                </div>
            </div>
        </div>
    );
};

import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { FileText, Calendar, ChevronRight, Phone } from 'lucide-react';
import SharedImage from '@/components/common/Image';
import { Button, Badge } from '@/components/ui';
import { formatDate, formatCurrency } from '@/utils/format';
import { quoteService, type QuoteDto } from '@/services/quoteService';
// import { QuoteRequest } from '@/types'; // Remove or unused
import { Link } from 'react-router-dom';

const QuotesContent = () => {
  const { t } = useTranslation();
  const [quotes, setQuotes] = useState<QuoteDto[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    quoteService.getQuotes().then(res => {
      if (res.success && res.data) {
        setQuotes(res.data);
      }
      setLoading(false);
    });
  }, []);

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'pending': return 'warning';
      case 'quoted': return 'info';
      case 'closed': return 'success';
      case 'cancelled': return 'error';
      default: return 'secondary';
    }
  };

  const getStatusText = (status: string) => {
    switch (status) {
      case 'pending': return 'admin.status.pending'; // or specific quote keys if they exist, but admin keys work for common terms
      case 'quoted': return 'admin.status.quoted';
      case 'closed': return 'admin.status.closed';
      case 'cancelled': return 'admin.status.cancelled';
      default: return status;
    }
  };

  if (loading) return <div>{t('common.loading')}</div>;

  return (
    <div className="space-y-4">
      <h2 className="text-xl font-bold">{t('account.quotes')}</h2>

      {quotes.length === 0 && (
        <div className="text-center py-8">
          <p className="text-secondary mb-4">{t('account.noQuotes')}</p>
          <Link to="/products" className="text-primary hover:underline">{t('account.viewProductsToQuote')}</Link>
        </div>
      )}

      {quotes.map((quote) => (
        <div key={quote.code} className="bg-primary rounded-xl p-4 border border-secondary/20 hover:shadow-md transition-shadow">
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-2 mb-4">
            <div>
              <p className="font-semibold text-color-primary">#{quote.code.substring(0, 8)}</p>
              <p className="text-sm text-tertiary">{formatDate(quote.createdAt)}</p>
            </div>
            <span
              className={`px-3 py-1 rounded-full text-xs font-semibold bg-${getStatusColor(quote.status)}/20 text-${getStatusColor(quote.status)}`}
            >
              {t(getStatusText(quote.status))}
            </span>
          </div>

          <div className="flex gap-4 mb-4">
            <SharedImage
              src={quote.productImage}
              alt={quote.productName}
              className="w-16 h-16 object-cover rounded-md"
            />
            <div className="flex-1 min-w-0">
              <p className="text-base font-medium truncate text-color-primary">{quote.productName}</p>
              <p className="text-sm text-tertiary">{t('common.fields.quantity')}: {quote.quantity}</p>
              {quote.note && <p className="text-sm text-secondary italic">" {quote.note} "</p>}
            </div>
          </div>

          {quote.quotedPrice && (
            <div className="flex justify-between items-center pt-4 border-t border-secondary/10">
              <span className="text-sm text-secondary">{t('common.fields.quotedPrice')}</span>
              <span className="font-bold text-lg text-primary">{formatCurrency(quote.quotedPrice)}</span>
            </div>
          )}
        </div>
      ))}
    </div>
  );
};

